  1→import { stringify, parse } from "yaml";
  2→import { generateMermaid } from "@/lib/mermaid/generate";
  3→import type { FlowNode, FlowEdge } from "@/store/types";
  4→import type { FlowDirection, ComponentDefinition } from "@/types/flow";
  5→import type { FlowmaidLayout, FlowmaidNodeLayout, FlowmaidEdgeLayout } from "./schema";
  6→
  7→export interface SerializeOptions {
  8→  /** Include component definitions that have no instances on canvas (default: true) */
  9→  includeUnusedDefinitions?: boolean;
 10→}
 11→
 12→export function serialize(
 13→  nodes: FlowNode[],
 14→  edges: FlowEdge[],
 15→  direction: FlowDirection,
 16→  componentDefinitions?: ComponentDefinition[],
 17→  options?: SerializeOptions
 18→): string {
 19→  const { includeUnusedDefinitions = true } = options ?? {};
 20→
 21→  // Filter to only definitions that have instances on the canvas
 22→  const usedDefinitions = componentDefinitions && !includeUnusedDefinitions
 23→    ? filterUsedDefinitions(nodes, componentDefinitions)
 24→    : componentDefinitions;
 25→
 26→  const mermaidSection = generateMermaid(nodes, edges, direction, usedDefinitions);
 27→
 28→  const nodesLayout: Record<string, FlowmaidNodeLayout> = {};
 29→  for (const node of nodes) {
 30→    // Skip component child nodes (they're regenerated from definition)
 31→    if (node.data.componentParentId) continue;
 32→    const styleW = (node.style as Record<string, unknown>)?.width as number | undefined;
 33→    const styleH = (node.style as Record<string, unknown>)?.height as number | undefined;
 34→    const w = node.width ?? styleW;
 35→    const h = node.height ?? styleH;
 36→
 37→    const entry: FlowmaidNodeLayout = {
 38→      position: { x: node.position.x, y: node.position.y },
 39→      size: w && h ? { width: w, height: h } : undefined,
 40→      shape: node.data.shape,
 41→      label: node.data.label,
 42→    };
 43→    if (node.data.fillColor) entry.fillColor = node.data.fillColor;
 44→    if (node.data.fillOpacity !== undefined && node.data.fillOpacity !== 10) entry.fillOpacity = node.data.fillOpacity;
 45→    if (node.data.fillLightness !== undefined && node.data.fillLightness !== 5) entry.fillLightness = node.data.fillLightness;
 46→    if (node.data.borderColor) entry.borderColor = node.data.borderColor;
 47→    if (node.data.borderOpacity !== undefined && node.data.borderOpacity !== 10) entry.borderOpacity = node.data.borderOpacity;
 48→    if (node.data.borderLightness !== undefined && node.data.borderLightness !== 5) entry.borderLightness = node.data.borderLightness;
 49→    if (node.data.borderWidth) entry.borderWidth = node.data.borderWidth;
 50→    if (node.data.borderStyle) entry.borderStyle = node.data.borderStyle;
 51→    if (node.zIndex !== undefined && node.zIndex !== 0) entry.zIndex = node.zIndex;
 52→    if (node.data.fontSize) entry.fontSize = node.data.fontSize;
 53→    if (node.data.textColor) entry.textColor = node.data.textColor;
 54→    if (node.data.textOpacity !== undefined && node.data.textOpacity !== 10) entry.textOpacity = node.data.textOpacity;
 55→    if (node.data.textLightness !== undefined && node.data.textLightness !== 5) entry.textLightness = node.data.textLightness;
 56→    if (node.data.textAlign && node.data.textAlign !== "center") entry.textAlign = node.data.textAlign;
 57→    if (node.data.textVerticalAlign && node.data.textVerticalAlign !== "middle") entry.textVerticalAlign = node.data.textVerticalAlign;
 58→    if (node.data.bold) entry.bold = node.data.bold;
 59→    if (node.data.italic) entry.italic = node.data.italic;
 60→    if (node.data.underline) entry.underline = node.data.underline;
 61→    if (node.data.componentDefinitionId) entry.componentDefinitionId = node.data.componentDefinitionId as string;
 62→    if (node.data.componentInstanceName) entry.componentInstanceName = node.data.componentInstanceName as string;
 63→    if (node.data.componentSyncVersion !== undefined) entry.componentSyncVersion = node.data.componentSyncVersion as number;
 64→    if (node.data.collapsed) entry.collapsed = true;
 65→    if (node.data.expandedSize) entry.expandedSize = node.data.expandedSize as { width: number; height: number };
 66→
 67→    nodesLayout[node.id] = entry;
 68→  }
 69→
 70→  // Build set of component child node IDs to filter internal edges
 71→  const componentChildIds = new Set(nodes.filter((n) => n.data.componentParentId).map((n) => n.id));
 72→
 73→  const edgesLayout: Record<string, FlowmaidEdgeLayout> = {};
 74→  for (const edge of edges) {
 75→    // Skip bridge edges
 76→    if (edge.data?.isBridgeEdge) continue;
 77→    // Skip internal edges between component children
 78→    if (componentChildIds.has(edge.source) && componentChildIds.has(edge.target)) continue;
 79→    const entry: FlowmaidEdgeLayout = {
 80→      source: edge.source,
 81→      target: edge.target,
 82→    };
 83→    if (edge.data?.label) entry.label = edge.data.label;
 84→    if (edge.sourceHandle) entry.sourceHandle = edge.sourceHandle;
 85→    if (edge.targetHandle) entry.targetHandle = edge.targetHandle;
 86→    if (edge.data?.edgeType && edge.data.edgeType !== "bezier") entry.edgeType = edge.data.edgeType;
 87→    if (edge.data?.markerStart) entry.markerStart = edge.data.markerStart;
 88→    if (edge.data?.markerEnd && edge.data.markerEnd !== "arrowclosed") entry.markerEnd = edge.data.markerEnd;
 89→    if (edge.data?.strokeWidth && edge.data.strokeWidth !== 2) entry.strokeWidth = edge.data.strokeWidth;
 90→    if (edge.data?.strokeColor) entry.strokeColor = edge.data.strokeColor;
 91→    if (edge.data?.strokeOpacity !== undefined && edge.data.strokeOpacity !== 10) entry.strokeOpacity = edge.data.strokeOpacity;
 92→    if (edge.data?.strokeLightness !== undefined && edge.data.strokeLightness !== 5) entry.strokeLightness = edge.data.strokeLightness;
 93→    if (edge.data?.strokeStyle && edge.data.strokeStyle !== "solid") entry.strokeStyle = edge.data.strokeStyle;
 94→    if (edge.data?.waypoints && edge.data.waypoints.length > 0) entry.waypoints = edge.data.waypoints;
 95→
 96→    edgesLayout[edge.id] = entry;
 97→  }
 98→
 99→  const layout: FlowmaidLayout = {
100→    direction,
101→    nodes: nodesLayout,
102→    edges: edgesLayout,
103→    ...(usedDefinitions && usedDefinitions.length > 0 && { componentDefinitions: usedDefinitions }),
104→  };
105→
106→  const layoutSection = stringify(layout);
107→
108→  return `--- mermaid ---\n${mermaidSection}\n\n--- layout ---\n${layoutSection}`;
109→}
110→
111→/**
112→ * Serialize only the selected nodes/edges (+ related edges) for filtered preview.
113→ * Returns the same format as serialize() but with only the relevant layout entries.
114→ * Mermaid section is always included in full.
115→ */
116→export function serializeFiltered(
117→  nodes: FlowNode[],
118→  edges: FlowEdge[],
119→  direction: FlowDirection,
120→  componentDefinitions: ComponentDefinition[] | undefined,
121→  selectedNodeIds: string[],
122→  selectedEdgeIds: string[]
123→): string {
124→  const full = serialize(nodes, edges, direction, componentDefinitions);
125→  if (selectedNodeIds.length === 0 && selectedEdgeIds.length === 0) return full;
126→
127→  const parts = full.split("--- layout ---\n");
128→  if (parts.length < 2) return full;
129→
130→  const mermaidPart = parts[0];
131→  const layoutYaml = parts[1];
132→
133→  const layout = parse(layoutYaml) as FlowmaidLayout | null;
134→  if (!layout) return full;
135→
136→  const nodeIdSet = new Set(selectedNodeIds);
137→  const edgeIdSet = new Set(selectedEdgeIds);
138→
139→  const filteredLayout: FlowmaidLayout = {
140→    direction: layout.direction,
141→    nodes: {},
142→    edges: {},
143→  };
144→
145→  if (layout.nodes) {
146→    for (const [id, node] of Object.entries(layout.nodes)) {
147→      if (nodeIdSet.has(id)) filteredLayout.nodes[id] = node;
148→    }
149→  }
150→  if (layout.edges) {
151→    for (const [id, edge] of Object.entries(layout.edges)) {
152→      if (edgeIdSet.has(id)) filteredLayout.edges[id] = edge;
153→    }
154→  }
155→  if (layout.componentDefinitions) {
156→    filteredLayout.componentDefinitions = layout.componentDefinitions;
157→  }
158→
159→  const filteredSection = stringify(filteredLayout);
160→
161→  return `${mermaidPart}--- layout ---\n${filteredSection}`;
162→}
163→
164→/**
165→ * Filter component definitions to only those that have instances on the canvas.
166→ */
167→export function filterUsedDefinitions(
168→  nodes: FlowNode[],
169→  definitions: ComponentDefinition[]
170→): ComponentDefinition[] {
171→  const usedDefIds = new Set(
172→    nodes
173→      .filter((n) => n.type === "componentInstance" && n.data.componentDefinitionId)
174→      .map((n) => n.data.componentDefinitionId as string)
175→  );
176→  return definitions.filter((d) => usedDefIds.has(d.id));
177→}
