 20→function shapeDefaultSize(shape: string): { width: number; height: number } {
 21→  if (shape === "diamond") return { width: DEFAULT_DIAMOND_SIZE, height: DEFAULT_DIAMOND_SIZE };
 22→  if (shape === "circle") return { width: DEFAULT_NODE_HEIGHT * 2, height: DEFAULT_NODE_HEIGHT * 2 };
 23→  if (shape === "hexagon") return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT + 10 };
 24→  if (shape === "cylinder") return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 20 };
 25→  if (shape === "document") return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 10 };
 26→  if (shape === "predefinedProcess" || shape === "display") return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 27→  return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT };
 28→}
 29→
 30→function markerStyleToMarker(style?: MarkerStyle, color?: string) {
 31→  switch (style) {
 32→    case "arrow":
 33→      return color ? { type: MarkerType.Arrow, color } : { type: MarkerType.Arrow };
 34→    case "arrowclosed":
 35→      return color ? { type: MarkerType.ArrowClosed, color } : { type: MarkerType.ArrowClosed };
 36→    case "none":
 37→      return undefined;
 38→    default:
 39→      return undefined;
 40→  }
 41→}
 42→
 43→function reconcileBridgeEdges(nodes: FlowNode[], edges: FlowEdge[], defs: ComponentDefinition[], direction: FlowDirection = "TD"): FlowEdge[] {
 44→  // Remove all existing bridge edges
 45→  const nonBridgeEdges = edges.filter((e) => !e.data?.isBridgeEdge);
 46→
 47→  // Generate bridge edges for all component instances
 48→  const allBridgeEdges: FlowEdge[] = [];
 49→  for (const node of nodes) {
 50→    if (node.type !== "componentInstance" || !node.data.componentDefinitionId) continue;
 51→    const def = defs.find((d) => d.id === node.data.componentDefinitionId);
 52→    if (!def) continue;
 53→
 54→    const bridges = generateBridgeEdges({
 55→      parentId: node.id,
 56→      def,
 57→      allEdges: nonBridgeEdges,
 58→      direction: def.direction ?? direction,
 59→    });
 60→
 61→    // If instance is collapsed, hide bridge edges
 62→    const isCollapsed = node.data.collapsed ?? false;
 63→    for (const b of bridges) {
 64→      if (isCollapsed) b.hidden = true;
 65→      allBridgeEdges.push(b);
 66→    }
 67→  }
 68→
 69→  return [...nonBridgeEdges, ...allBridgeEdges];
 70→}
