 72→const initialState = {
 73→  nodes: [] as FlowNode[],
 74→  edges: [] as FlowEdge[],
 75→  direction: "TD" as const,
 76→  nextIdCounter: 0,
 77→  componentDefinitions: [] as ComponentDefinition[],
 78→  editingComponentId: null as string | null,
 79→  savedMainFlow: null as import("./types").SavedMainFlow | null,
 80→  previewStyle: null as import("./types").PreviewStyle | null,
 81→  predictiveInput: {
