 90→export const useFlowStore = create<FlowState>()(
 91→  temporal(
 92→    (set, get) => ({
 93→      ...initialState,
 94→
 95→      addNode: (shape: string, position?: { x: number; y: number }) => {
 96→        const counter = get().nextIdCounter;
 97→        const id = counterToId(counter);
 98→
 99→        let width = DEFAULT_NODE_WIDTH;
100→        let height = DEFAULT_NODE_HEIGHT;
101→        if (shape === "diamond") {
102→          width = DEFAULT_DIAMOND_SIZE;
103→          height = DEFAULT_DIAMOND_SIZE;
104→        } else if (shape === "circle") {
105→          width = DEFAULT_NODE_HEIGHT * 2;
106→          height = DEFAULT_NODE_HEIGHT * 2;
107→        } else if (shape === "hexagon") {
108→          width = DEFAULT_NODE_WIDTH + 20;
109→          height = DEFAULT_NODE_HEIGHT + 10;
110→        } else if (shape === "cylinder") {
111→          width = DEFAULT_NODE_WIDTH;
112→          height = DEFAULT_NODE_HEIGHT + 20;
113→        } else if (shape === "document") {
114→          width = DEFAULT_NODE_WIDTH;
115→          height = DEFAULT_NODE_HEIGHT + 10;
116→        } else if (shape === "predefinedProcess") {
117→          width = DEFAULT_NODE_WIDTH + 20;
118→          height = DEFAULT_NODE_HEIGHT;
119→        } else if (shape === "display") {
120→          width = DEFAULT_NODE_WIDTH + 20;
121→          height = DEFAULT_NODE_HEIGHT;
122→        } else if (shape === "text") {
123→          width = DEFAULT_NODE_WIDTH;
124→          height = DEFAULT_NODE_HEIGHT;
125→        }
126→
127→        const isText = shape === "text";
128→        const newNode: FlowNode = {
129→          id,
130→          type: shape,
131→          position: position ?? { x: 250, y: 150 },
132→          data: {
133→            label: isText ? "Text" : id,
134→            shape: shape as NodeShape,
135→            ...(isText && { fillOpacity: 0, borderOpacity: 0 }),
136→          },
137→          style: { width, height },
138→        };
139→
140→        set({
141→          nodes: [...get().nodes, newNode],
142→          nextIdCounter: counter + 1,
143→        });
144→      },
145→
146→      removeNodes: (ids: string[]) => {
147→        const { nodes, edges, editingComponentId } = get();
148→        // In component editing mode, protect locked (entry/exit) nodes
149→        const protectedIds = editingComponentId
150→          ? new Set(nodes.filter((n) => n.data.isLocked).map((n) => n.id))

146→      removeNodes: (ids: string[]) => {
147→        const { nodes, edges, editingComponentId } = get();
148→        // In component editing mode, protect locked (entry/exit) nodes
149→        const protectedIds = editingComponentId
150→          ? new Set(nodes.filter((n) => n.data.isLocked).map((n) => n.id))
151→          : new Set<string>();
152→        const idSet = new Set(ids.filter((id) => !protectedIds.has(id)));
153→        if (idSet.size === 0) return;
154→        // Also remove children of component instances being deleted
155→        for (const n of nodes) {
156→          if (n.data.componentParentId && idSet.has(n.data.componentParentId as string)) {
157→            idSet.add(n.id);
158→          }
159→        }
160→        set({
161→          nodes: nodes.filter((n) => !idSet.has(n.id)),
162→          edges: edges.filter(
163→            (e) => !idSet.has(e.source) && !idSet.has(e.target)
164→          ),
165→        });
166→      },
167→
168→      updateNodeLabel: (id: string, label: string, autoResize?: "expand" | "both" | "none") => {
169→        // In component editing mode, protect locked (entry/exit) nodes
170→        const node = get().nodes.find((n) => n.id === id);
171→        if (node?.data.isLocked && get().editingComponentId) return;
172→        const mode = autoResize ?? "expand";
173→        set({
174→          nodes: get().nodes.map((n) => {
175→            if (n.id !== id) return n;
176→            const updated = { ...n, data: { ...n.data, label } };
177→            if (mode === "none") return updated;
178→            // Auto-resize height for multiline text
179→            const lineCount = label.split("\n").length;
180→            const fontSize = n.data.fontSize ?? 14;
181→            const lineHeight = fontSize * 1.5;
182→            const padding = 20; // vertical padding
183→            const currentH = (n.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
184→            if (lineCount > 1) {
185→              const minHeight = padding + lineCount * lineHeight;
186→              if (mode === "both" || minHeight > currentH) {
187→                updated.style = { ...n.style, height: Math.round(minHeight) };
188→              }
189→            } else if (mode === "both") {
190→              // Single line: shrink back to default height for the shape
191→              const defaultH = DEFAULT_NODE_HEIGHT;
192→              if (currentH > defaultH) {
193→                updated.style = { ...n.style, height: defaultH };
194→              }
195→            }
196→            return updated;
197→          }),
198→        });
199→      },
200→
201→      updateNodeId: (oldId: string, newId: string) => {
202→        const { nodes, edges } = get();
203→        if (oldId === newId) return true;
204→        if (nodes.some((n) => n.id === newId)) return false;
205→
206→        set({
207→          nodes: nodes.map((n) =>
208→            n.id === oldId ? { ...n, id: newId } : n
209→          ),
210→          edges: edges.map((e) => ({
211→            ...e,
212→            id:
213→              e.source === oldId || e.target === oldId
214→                ? `${e.source === oldId ? newId : e.source}-${e.target === oldId ? newId : e.target}`
215→                : e.id,
216→            source: e.source === oldId ? newId : e.source,
217→            target: e.target === oldId ? newId : e.target,
218→          })),
219→        });
220→        return true;
221→      },
222→
223→      updateNodeColors: (id: string, fillColor?: string | null, borderColor?: string | null) => {
224→        set({
225→          nodes: get().nodes.map((n) => {
226→            if (n.id !== id) return n;
227→            const newData = { ...n.data };
228→            if (fillColor !== undefined) newData.fillColor = fillColor ?? undefined;
229→            if (borderColor !== undefined) newData.borderColor = borderColor ?? undefined;
230→            return { ...n, data: newData };
231→          }),
232→        });
233→      },
234→
235→      updateNodeBorder: (id: string, borderWidth?: number, borderStyle?: BorderStyle) => {
236→        set({
237→          nodes: get().nodes.map((n) => {
238→            if (n.id !== id) return n;
239→            const newData = { ...n.data };
240→            if (borderWidth !== undefined) newData.borderWidth = borderWidth;
241→            if (borderStyle !== undefined) newData.borderStyle = borderStyle;
242→            return { ...n, data: newData };
243→          }),
244→        });
245→      },

