 45→  for (const [id, n] of Object.entries(layout.nodes)) {
 46→    const isComponentInstance = !!n.componentDefinitionId;
 47→    const node: FlowNode = {
 48→      id,
 49→      type: isComponentInstance ? "componentInstance" : n.shape,
 50→      position: n.position,
 51→      data: {
 52→        label: n.label,
 53→        shape: n.shape as FlowNode["data"]["shape"],
 54→      },
 55→      style: n.size ? { width: n.size.width, height: n.size.height } : undefined,
 56→    };
 57→
 58→    // Restore component instance fields
 59→    if (n.componentDefinitionId) node.data.componentDefinitionId = n.componentDefinitionId;
 60→    if (n.componentInstanceName) node.data.componentInstanceName = n.componentInstanceName;
 61→    if (n.componentSyncVersion !== undefined) node.data.componentSyncVersion = n.componentSyncVersion;
 62→    // componentLabelOverrides is deprecated — ignored on import
 63→    if (n.collapsed) node.data.collapsed = n.collapsed;
 64→    if (n.expandedSize) node.data.expandedSize = n.expandedSize;
 65→
 66→    // Restore style properties
 67→    if (n.fillColor) node.data.fillColor = n.fillColor;
 68→    if (n.fillOpacity !== undefined) node.data.fillOpacity = n.fillOpacity;
 69→    if (n.fillLightness !== undefined) node.data.fillLightness = n.fillLightness;
 70→    if (n.borderColor) node.data.borderColor = n.borderColor;
 71→    if (n.borderOpacity !== undefined) node.data.borderOpacity = n.borderOpacity;
 72→    if (n.borderLightness !== undefined) node.data.borderLightness = n.borderLightness;
 73→    if (n.borderWidth) node.data.borderWidth = n.borderWidth;
 74→    if (n.borderStyle) node.data.borderStyle = n.borderStyle;
 75→    if (n.zIndex !== undefined) node.zIndex = n.zIndex;
 76→    if (n.fontSize) node.data.fontSize = n.fontSize;
 77→    if (n.textColor) node.data.textColor = n.textColor;
 78→    if (n.textOpacity !== undefined) node.data.textOpacity = n.textOpacity;
 79→    if (n.textLightness !== undefined) node.data.textLightness = n.textLightness;
 80→    if (n.textAlign) node.data.textAlign = n.textAlign;
 81→    if (n.textVerticalAlign) node.data.textVerticalAlign = n.textVerticalAlign;
 82→    if (n.bold) node.data.bold = n.bold;
 83→    if (n.italic) node.data.italic = n.italic;
 84→    if (n.underline) node.data.underline = n.underline;
 85→
 86→    nodes.push(node);
 87→
 88→    // Track highest counter for auto-id
 89→    if (/^[A-Z]+$/.test(id)) {
 90→      const counter = idToCounter(id);
 91→      if (counter > maxCounter) maxCounter = counter;
 92→    }
 93→  }
 94→
 95→  const edges: FlowEdge[] = [];
 96→  for (const [id, e] of Object.entries(layout.edges)) {
 97→    const edge: FlowEdge = {
 98→      id,
 99→      source: e.source,
100→      target: e.target,
101→      type: "labeled",
102→      sourceHandle: e.sourceHandle,
103→      targetHandle: e.targetHandle,
104→      data: {
105→        label: e.label ?? "",
106→        edgeType: e.edgeType ?? "bezier",
107→        markerStart: e.markerStart,
108→        markerEnd: e.markerEnd ?? "arrowclosed",
109→        strokeWidth: e.strokeWidth,
110→        strokeColor: e.strokeColor,
111→        strokeOpacity: e.strokeOpacity,
112→        strokeLightness: e.strokeLightness,
113→        strokeStyle: e.strokeStyle,
114→        waypoints: e.waypoints,
115→      },
116→    };
117→
118→    edges.push(edge);
119→  }
120→
121→  // Regenerate child nodes and internal edges for component instances
122→  const componentDefinitions = layout.componentDefinitions ?? [];
123→
124→  const allChildNodes: FlowNode[] = [];
125→  const allChildEdges: FlowEdge[] = [];
126→
127→  for (const node of nodes) {
128→    if (!node.data.componentDefinitionId) continue;
129→    const def = componentDefinitions.find((d) => d.id === node.data.componentDefinitionId);
130→    if (!def) continue;
131→
132→    // Populate runtime-only direction field from definition
133→    if (def.direction) {
134→      node.data.componentDefinitionDirection = def.direction;
135→    }
136→
137→    const isCollapsed = node.data.collapsed ?? false;
138→
139→    const { childNodes, childEdges } = generateComponentChildren({
140→      parentId: node.id,
141→      def,
142→      hidden: isCollapsed,
143→    });
144→
145→    allChildNodes.push(...childNodes);
146→    allChildEdges.push(...childEdges);
147→  }
148→
149→  // Generate bridge edges for component instances
150→  const allNodes = [...nodes, ...allChildNodes];
151→  const allEdgesBeforeBridge = [...edges, ...allChildEdges];
152→  const bridgeEdges: FlowEdge[] = [];
153→
154→  for (const node of nodes) {
155→    if (!node.data.componentDefinitionId) continue;
156→    const def = componentDefinitions.find((d) => d.id === node.data.componentDefinitionId);
157→    if (!def) continue;
158→
159→    const bridges = generateBridgeEdges({
160→      parentId: node.id,
161→      def,
162→      allEdges: allEdgesBeforeBridge,
163→      direction: def.direction ?? layout.direction,
164→    });
165→
166→    const isCollapsed = node.data.collapsed ?? false;
167→    for (const b of bridges) {
168→      if (isCollapsed) b.hidden = true;
169→      bridgeEdges.push(b);
170→    }
171→  }
172→
173→  return {
174→    nodes: allNodes,
175→    edges: [...allEdgesBeforeBridge, ...bridgeEdges],
176→    direction: layout.direction ?? "TD",
177→    nextIdCounter: maxCounter + 1,
178→    componentDefinitions,
179→  };
