export const NodeShape = {
  Rectangle: "rectangle",
  Diamond: "diamond",
  RoundedRect: "roundedRect",
  Circle: "circle",
  Parallelogram: "parallelogram",
  Cylinder: "cylinder",
  Hexagon: "hexagon",
  Stadium: "stadium",
  Trapezoid: "trapezoid",
  Document: "document",
  PredefinedProcess: "predefinedProcess",
  ManualInput: "manualInput",
  InternalStorage: "internalStorage",
  Display: "display",
  Text: "text",
} as const;

export type NodeShape = (typeof NodeShape)[keyof typeof NodeShape];

export const FlowDirection = {
  TopDown: "TD",
  LeftRight: "LR",
} as const;

export type FlowDirection =
  (typeof FlowDirection)[keyof typeof FlowDirection];

export const EdgeType = {
  Bezier: "bezier",
  Straight: "straight",
  Step: "step",
} as const;

export type EdgeType = (typeof EdgeType)[keyof typeof EdgeType];

export const MarkerStyle = {
  Arrow: "arrow",
  ArrowClosed: "arrowclosed",
  None: "none",
} as const;

export type MarkerStyle = (typeof MarkerStyle)[keyof typeof MarkerStyle];

export type BorderStyle = "solid" | "dashed" | "dotted";
export type StrokeStyle = "solid" | "dashed" | "dotted";

export type TextAlign = "left" | "center" | "right";
export type TextVerticalAlign = "top" | "middle" | "bottom";

// Component definition types
export interface ComponentInternalNode {
  id: string;
  label: string;
  shape: NodeShape;
  position: { x: number; y: number };
  style?: { width: number; height: number };
  fillColor?: string;
  fillOpacity?: number;
  fillLightness?: number;
  borderColor?: string;
  borderOpacity?: number;
  borderLightness?: number;
  borderWidth?: number;
  borderStyle?: BorderStyle;
  fontSize?: number;
  textColor?: string;
  textOpacity?: number;
  textLightness?: number;
  textAlign?: TextAlign;
  textVerticalAlign?: TextVerticalAlign;
  bold?: boolean;
  italic?: boolean;
  underline?: boolean;
}

export interface ComponentInternalEdge {
  id: string;
  source: string;
  target: string;
  label?: string;
  sourceHandle?: string;
  targetHandle?: string;
  edgeType?: EdgeType;
  markerStart?: MarkerStyle;
  markerEnd?: MarkerStyle;
  strokeWidth?: number;
  strokeColor?: string;
  strokeOpacity?: number;
  strokeLightness?: number;
  strokeStyle?: StrokeStyle;
}

export interface ComponentDefinition {
  id: string;
  name: string;
  version: number;
  direction?: FlowDirection;
  nodes: ComponentInternalNode[];
  edges: ComponentInternalEdge[];
  entryNodeId: string | null;
  exitNodeId: string | null;
}

