      bridgeEdges.push(b);
    }
  }

  return {
    nodes: allNodes,
    edges: [...allEdgesBeforeBridge, ...bridgeEdges],
    direction: layout.direction ?? "TD",
    nextIdCounter: maxCounter + 1,
    componentDefinitions,
  };
}

