    if (subgraphMatch) {
      const sgId = subgraphMatch[1];
      const sgLabel = subgraphMatch[2] ? unescapeMermaid(subgraphMatch[2]) : sgId;
      subgraphStack.push({ id: sgId, label: sgLabel });
      subgraphLabels.set(sgId, sgLabel);
      subgraphNodes.set(sgId, []);
