      if (subgraphStack.length > 0) {
        subgraphParentMap.set(sgId, subgraphStack[subgraphStack.length - 1].id);
      }
      subgraphStack.push({ id: sgId, label: sgLabel });
      subgraphLabels.set(sgId, sgLabel);
      continue;
