  if (layout) {
    // Use mermaid.js layout result
    positions = new Map<string, { x: number; y: number }>();
    backEdges = new Set<string>();

    for (const [id, def] of nodeDefs) {
      const mNode = layout.nodes.get(id);
      if (mNode) {
        // mermaid.js returns center coordinates; convert to top-left
        positions.set(id, {
          x: mNode.x - mNode.width / 2,
          y: mNode.y - mNode.height / 2,
        });
        sizeMap.set(id, { width: mNode.width, height: mNode.height });
      } else {
        const size = getNodeSize(def.shape);
        positions.set(id, { x: 0, y: 0 });
        sizeMap.set(id, size);
      }
    }
  } else {
    // Fall back to autoLayout
    const nodeIds = [...nodeDefs.keys()].map((id) => ({ id }));
    for (const [id, def] of nodeDefs) {
      sizeMap.set(id, getNodeSize(def.shape));
    }
    const layoutResult = autoLayout(nodeIds, edgeList, direction, sizeMap);
    positions = layoutResult.positions;
    backEdges = layoutResult.backEdges;
  }

  // Build FlowNode[]
  const nodes: FlowNode[] = [];
  let maxCounter = 0;

  for (const [id, def] of nodeDefs) {
    const pos = positions.get(id) ?? { x: 0, y: 0 };
    const size = sizeMap.get(id) ?? getNodeSize(def.shape);

    // Track highest alphabetic ID counter
    if (/^[A-Z]+$/.test(id)) {
      let counter = 0;
      for (let c = 0; c < id.length; c++) {
        counter = counter * 26 + (id.charCodeAt(c) - 64);
      }
      counter -= 1;
      if (counter + 1 > maxCounter) maxCounter = counter + 1;
    }

    nodes.push({
      id,
      type: def.shape,
      position: pos,
      data: { label: def.label, shape: def.shape },
      style: { width: size.width, height: size.height },
    });
  }

  // Handle directions: forward edges follow main axis, back-edges loop via cross axis
  const fwdSourceHandle = direction === "LR" ? "right-source" : "bottom-source";
  const fwdTargetHandle = direction === "LR" ? "left-target" : "top-target";
  const backSourceHandle = direction === "LR" ? "bottom-source" : "right-source";
  const backTargetHandle = direction === "LR" ? "bottom-target" : "right-target";

  // Build FlowEdge[]
  const edges: FlowEdge[] = [];
  for (const e of edgeList) {
    const isBack = backEdges.has(`${e.source}->${e.target}`);
    const sh = isBack ? backSourceHandle : fwdSourceHandle;
    const th = isBack ? backTargetHandle : fwdTargetHandle;
    const edgeId = `${e.source}-${e.target}-${sh}-${th}`;
    edges.push({
      id: edgeId,
      source: e.source,
      target: e.target,
      sourceHandle: sh,
      targetHandle: th,
      type: "labeled",
      markerEnd: { type: MarkerType.ArrowClosed },
      data: {
        label: e.label,
        edgeType: edgeType ?? "bezier",
        markerEnd: "arrowclosed",
      },
    });
  }

  // Convert subgraphs to subgraphGroup nodes with child parentId relationships
  for (const [sgId, sgLabel] of subgraphLabels) {
    // Collect direct child node IDs for this subgraph
    const childIds = new Set<string>();
    for (const [nodeId, parentSgId] of nodeToSubgraph) {
      if (parentSgId === sgId) childIds.add(nodeId);
    }
    // Also include nested subgraph group nodes whose parent is this subgraph
    for (const [nestedSgId, parentSgId] of subgraphParentMap) {
      if (parentSgId === sgId) childIds.add(nestedSgId);
    }

    // Get child node positions to compute bounding box
    const childNodes = nodes.filter((n) => childIds.has(n.id));
    if (childNodes.length === 0) {
      // Empty subgraph: create at default position
      nodes.push({
        id: sgId,
        type: "subgraphGroup",
        position: { x: 0, y: 0 },
        data: { label: sgLabel, shape: "rectangle" as NodeShape, isSubgraphGroup: true },
        style: { width: 200, height: 100 },
        zIndex: -1,
      });
      continue;
    }

    // Use mermaid.js subgraph layout if available
    let sgPos: { x: number; y: number };
    let sgSize: { width: number; height: number };

    const sgLayout = layout?.subgraphs.get(sgId);
    if (sgLayout) {
      sgPos = { x: sgLayout.x, y: sgLayout.y };
      sgSize = { width: sgLayout.width, height: sgLayout.height };
    } else {
      // Compute bounding box from child positions
      let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
      for (const child of childNodes) {
        const w = (child.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
        const h = (child.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
        if (child.position.x < minX) minX = child.position.x;
        if (child.position.y < minY) minY = child.position.y;
        if (child.position.x + w > maxX) maxX = child.position.x + w;
        if (child.position.y + h > maxY) maxY = child.position.y + h;
      }
      sgPos = {
        x: minX - SUBGRAPH_PADDING_X,
        y: minY - SUBGRAPH_PADDING_Y_TOP,
      };
      sgSize = {
        width: (maxX - minX) + SUBGRAPH_PADDING_X * 2,
        height: (maxY - minY) + SUBGRAPH_PADDING_Y_TOP + SUBGRAPH_PADDING_Y_BOTTOM,
      };
    }

    // Create subgraphGroup node
    const sgNode: FlowNode = {
      id: sgId,
      type: "subgraphGroup",
      position: sgPos,
      data: { label: sgLabel, shape: "rectangle" as NodeShape, isSubgraphGroup: true },
      style: { width: sgSize.width, height: sgSize.height },
      zIndex: -1,
    };

    // If this subgraph is nested inside another, set parentId
    const parentSgId = subgraphParentMap.get(sgId);
    if (parentSgId) {
      sgNode.parentId = parentSgId;
      sgNode.data.subgraphParentId = parentSgId;
    }

    nodes.push(sgNode);

    // Convert child nodes: set parentId and convert to relative coordinates
    for (const child of childNodes) {
      child.parentId = sgId;
      child.data = { ...child.data, subgraphParentId: sgId };
      child.position = {
        x: child.position.x - sgPos.x,
        y: child.position.y - sgPos.y,
      };
    }
  }

  // For nested subgraphs, convert subgraphGroup positions to relative coordinates
  // Process from innermost to outermost (reverse order of subgraphLabels)
  const processedSgs = new Set<string>();
  const convertSubgraphToRelative = (sgId: string) => {
    if (processedSgs.has(sgId)) return;
    processedSgs.add(sgId);
    const parentSgId = subgraphParentMap.get(sgId);
    if (!parentSgId) return;
    // Ensure parent is processed first
    convertSubgraphToRelative(parentSgId);
    const sgNode = nodes.find((n) => n.id === sgId);
    const parentSgNode = nodes.find((n) => n.id === parentSgId);
    if (sgNode && parentSgNode) {
      // The parent's position is already absolute (or already relative to its parent)
      // Child nodes of this subgraph are already relative to sgNode
      // We need to make sgNode's position relative to parentSgNode
      // But parentSgNode might already have been converted to relative
      // Since we process parents first, parentSgNode.position is already relative
      // We need the absolute position of parentSgNode to compute relative
    }
  };

  // Simpler approach: convert nested subgraph group nodes' positions to relative
  // The child nodes within each subgraph are already relative to their parent
  // But subgraph group nodes that have a parentId need their position relative to their parent
  for (const [sgId, parentSgId] of subgraphParentMap) {
    const sgNode = nodes.find((n) => n.id === sgId);
    const parentSgNode = nodes.find((n) => n.id === parentSgId);
    if (sgNode && parentSgNode) {
      // sgNode.position is absolute, parentSgNode.position is absolute (or already relative)
      // Since parentSgNode's children are positioned relative to parentSgNode's absolute position
      // and parentSgNode has already been set up with its position,
      // we need sgNode position relative to parentSgNode
      const parentAbsX = parentSgNode.parentId ? 0 : parentSgNode.position.x;
      const parentAbsY = parentSgNode.parentId ? 0 : parentSgNode.position.y;
      sgNode.position = {
        x: sgNode.position.x - parentAbsX,
        y: sgNode.position.y - parentAbsY,
      };
    }
  }

  return {
    nodes,
    edges,
    direction,
    nextIdCounter: maxCounter,
  };
}

