    zIndex: -1,
  };

  // If this subgraph is nested inside another, set parentId
  const parentSgId = subgraphParentMap.get(sgId);
  if (parentSgId) {
    sgNode.parentId = parentSgId;
    sgNode.data.subgraphParentId = parentSgId;
  }

  nodes.push(sgNode);

  // Convert child nodes: set parentId and convert to relative coordinates
  for (const child of childNodes) {
    child.parentId = sgId;
    child.data = { ...child.data, subgraphParentId: sgId };
    child.position = {
      x: child.position.x - sgPos.x,
      y: child.position.y - sgPos.y,
    };
  }
}

// For nested subgraphs, convert subgraphGroup positions to relative coordinates
// Process from innermost to outermost (reverse order of subgraphLabels)
const processedSgs = new Set<string>();
const convertSubgraphToRelative = (sgId: string) => {
  if (processedSgs.has(sgId)) return;
  processedSgs.add(sgId);
  const parentSgId = subgraphParentMap.get(sgId);
  if (!parentSgId) return;
  // Ensure parent is processed first
  convertSubgraphToRelative(parentSgId);
  const sgNode = nodes.find((n) => n.id === sgId);
  const parentSgNode = nodes.find((n) => n.id === parentSgId);
  if (sgNode && parentSgNode) {
    // The parent's position is already absolute (or already relative to its parent)
    // Child nodes of this subgraph are already relative to sgNode
    // We need to make sgNode's position relative to parentSgNode
    // But parentSgNode might already have been converted to relative
    // Since we process parents first, parentSgNode.position is already relative
    // We need the absolute position of parentSgNode to compute relative
  }
};

// Simpler approach: convert nested subgraph group nodes' positions to relative
// The child nodes within each subgraph are already relative to their parent
// But subgraph group nodes that have a parentId need their position relative to their parent
for (const [sgId, parentSgId] of subgraphParentMap) {
  const sgNode = nodes.find((n) => n.id === sgId);
  const parentSgNode = nodes.find((n) => n.id === parentSgId);
  if (sgNode && parentSgNode) {
    // sgNode.position is absolute, parentSgNode.position is absolute (or already relative)
    // Since parentSgNode's children are positioned relative to parentSgNode's absolute position
    // and parentSgNode has already been set up with its position,
    // we need sgNode position relative to parentSgNode
    const parentAbsX = parentSgNode.parentId ? 0 : parentSgNode.position.x;
    const parentAbsY = parentSgNode.parentId ? 0 : parentSgNode.position.y;
    sgNode.position = {
      x: sgNode.position.x - parentAbsX,
      y: sgNode.position.y - parentAbsY,
    };
  }
}

