 12→export function serialize(
 13→  nodes: FlowNode[],
 14→  edges: FlowEdge[],
 15→  direction: FlowDirection,
 16→  componentDefinitions?: ComponentDefinition[],
 17→  options?: SerializeOptions
 18→): string {
 19→  const { includeUnusedDefinitions = true } = options ?? {};
 20→
 21→  // Filter to only definitions that have instances on the canvas
 22→  const usedDefinitions = componentDefinitions && !includeUnusedDefinitions
 23→    ? filterUsedDefinitions(nodes, componentDefinitions)
 24→    : componentDefinitions;
 25→
 26→  const mermaidSection = generateMermaid(nodes, edges, direction, usedDefinitions);
 27→
 28→  const nodesLayout: Record<string, FlowmaidNodeLayout> = {};
 29→  for (const node of nodes) {
 30→    // Skip component child nodes (they're regenerated from definition)
 31→    if (node.data.componentParentId) continue;
 32→    const styleW = (node.style as Record<string, unknown>)?.width as number | undefined;
 33→    const styleH = (node.style as Record<string, unknown>)?.height as number | undefined;
 34→    const w = node.width ?? styleW;
 35→    const h = node.height ?? styleH;
 36→
 37→    const entry: FlowmaidNodeLayout = {
 38→      position: { x: node.position.x, y: node.position.y },
 39→      size: w && h ? { width: w, height: h } : undefined,
 40→      shape: node.data.shape,
 41→      label: node.data.label,
 42→    };
 43→    if (node.data.fillColor) entry.fillColor = node.data.fillColor;
 44→    if (node.data.fillOpacity !== undefined && node.data.fillOpacity !== 10) entry.fillOpacity = node.data.fillOpacity;
 45→    if (node.data.fillLightness !== undefined && node.data.fillLightness !== 5) entry.fillLightness = node.data.fillLightness;
 46→    if (node.data.borderColor) entry.borderColor = node.data.borderColor;
 47→    if (node.data.borderOpacity !== undefined && node.data.borderOpacity !== 10) entry.borderOpacity = node.data.borderOpacity;
 48→    if (node.data.borderLightness !== undefined && node.data.borderLightness !== 5) entry.borderLightness = node.data.borderLightness;
 49→    if (node.data.borderWidth) entry.borderWidth = node.data.borderWidth;
 50→    if (node.data.borderStyle) entry.borderStyle = node.data.borderStyle;
 51→    if (node.zIndex !== undefined && node.zIndex !== 0) entry.zIndex = node.zIndex;
 52→    if (node.data.fontSize) entry.fontSize = node.data.fontSize;
 53→    if (node.data.textColor) entry.textColor = node.data.textColor;
 54→    if (node.data.textOpacity !== undefined && node.data.textOpacity !== 10) entry.textOpacity = node.data.textOpacity;
 55→    if (node.data.textLightness !== undefined && node.data.textLightness !== 5) entry.textLightness = node.data.textLightness;
 56→    if (node.data.textAlign && node.data.textAlign !== "center") entry.textAlign = node.data.textAlign;
 57→    if (node.data.textVerticalAlign && node.data.textVerticalAlign !== "middle") entry.textVerticalAlign = node.data.textVerticalAlign;
 58→    if (node.data.bold) entry.bold = node.data.bold;
 59→    if (node.data.italic) entry.italic = node.data.italic;
 60→    if (node.data.underline) entry.underline = node.data.underline;
 61→    if (node.data.componentDefinitionId) entry.componentDefinitionId = node.data.componentDefinitionId as string;
 62→    if (node.data.componentInstanceName) entry.componentInstanceName = node.data.componentInstanceName as string;
 63→    if (node.data.componentSyncVersion !== undefined) entry.componentSyncVersion = node.data.componentSyncVersion as number;
 64→    if (node.data.collapsed) entry.collapsed = true;
 65→    if (node.data.expandedSize) entry.expandedSize = node.data.expandedSize as { width: number; height: number };
 66→    if (node.data.isSubgraphGroup) entry.isSubgraphGroup = true;
 67→    if (node.data.subgraphParentId) entry.subgraphParentId = node.data.subgraphParentId as string;
 68→
 69→    nodesLayout[node.id] = entry;
 70→  }
 71→
 72→  // Build set of component child node IDs to filter internal edges
 73→  const componentChildIds = new Set(nodes.filter((n) => n.data.componentParentId).map((n) => n.id));
 74→
 75→  const edgesLayout: Record<string, FlowmaidEdgeLayout> = {};
 76→  for (const edge of edges) {
 77→    // Skip bridge edges
 78→    if (edge.data?.isBridgeEdge) continue;
 79→    // Skip internal edges between component children
 80→    if (componentChildIds.has(edge.source) && componentChildIds.has(edge.target)) continue;
 81→    const entry: FlowmaidEdgeLayout = {
 82→      source: edge.source,
 83→      target: edge.target,
 84→    };
 85→    if (edge.data?.label) entry.label = edge.data.label;
 86→    if (edge.sourceHandle) entry.sourceHandle = edge.sourceHandle;
 87→    if (edge.targetHandle) entry.targetHandle = edge.targetHandle;
 88→    if (edge.data?.edgeType && edge.data.edgeType !== "bezier") entry.edgeType = edge.data.edgeType;
 89→    if (edge.data?.markerStart) entry.markerStart = edge.data.markerStart;
 90→    if (edge.data?.markerEnd && edge.data.markerEnd !== "arrowclosed") entry.markerEnd = edge.data.markerEnd;
 91→    if (edge.data?.strokeWidth && edge.data.strokeWidth !== 2) entry.strokeWidth = edge.data.strokeWidth;
 92→    if (edge.data?.strokeColor) entry.strokeColor = edge.data.strokeColor;
 93→    if (edge.data?.strokeOpacity !== undefined && edge.data.strokeOpacity !== 10) entry.strokeOpacity = edge.data.strokeOpacity;
 94→    if (edge.data?.strokeLightness !== undefined && edge.data.strokeLightness !== 5) entry.strokeLightness = edge.data.strokeLightness;
 95→    if (edge.data?.strokeStyle && edge.data.strokeStyle !== "solid") entry.strokeStyle = edge.data.strokeStyle;
 96→    if (edge.data?.waypoints && edge.data.waypoints.length > 0) entry.waypoints = edge.data.waypoints;
 97→
 98→    edgesLayout[edge.id] = entry;
 99→  }
100→
101→  const layout: FlowmaidLayout = {
102→    direction,
103→    nodes: nodesLayout,
104→    edges: edgesLayout,
105→    ...(usedDefinitions && usedDefinitions.length > 0 && { componentDefinitions: usedDefinitions }),
106→  };
107→
108→  const layoutSection = stringify(layout);
109→
110→  return `--- mermaid ---\n${mermaidSection}\n\n--- layout ---\n${layoutSection}`;
111→}
