113→/**
114→ * Serialize only the selected nodes/edges (+ related edges) for filtered preview.
115→ * Returns the same format as serialize() but with only the relevant layout entries.
116→ * Mermaid section is always included in full.
117→ */
118→export function serializeFiltered(
119→  nodes: FlowNode[],
120→  edges: FlowEdge[],
121→  direction: FlowDirection,
122→  componentDefinitions: ComponentDefinition[] | undefined,
123→  selectedNodeIds: string[],
124→  selectedEdgeIds: string[]
125→): string {
126→  const full = serialize(nodes, edges, direction, componentDefinitions);
127→  if (selectedNodeIds.length === 0 && selectedEdgeIds.length === 0) return full;
128→
129→  const parts = full.split("--- layout ---\n");
130→  if (parts.length < 2) return full;
131→
132→  const mermaidPart = parts[0];
133→  const layoutYaml = parts[1];
134→
135→  const layout = parse(layoutYaml) as FlowmaidLayout | null;
136→  if (!layout) return full;
137→
138→  const nodeIdSet = new Set(selectedNodeIds);
139→  const edgeIdSet = new Set(selectedEdgeIds);
140→
141→  const filteredLayout: FlowmaidLayout = {
142→    direction: layout.direction,
143→    nodes: {},
144→    edges: {},
145→  };
146→
147→  if (layout.nodes) {
148→    for (const [id, node] of Object.entries(layout.nodes)) {
149→      if (nodeIdSet.has(id)) filteredLayout.nodes[id] = node;
150→    }
151→  }
152→  if (layout.edges) {
153→    for (const [id, edge] of Object.entries(layout.edges)) {
154→      if (edgeIdSet.has(id)) filteredLayout.edges[id] = edge;
155→    }
156→  }
157→  if (layout.componentDefinitions) {
158→    filteredLayout.componentDefinitions = layout.componentDefinitions;
159→  }
160→
161→  const filteredSection = stringify(filteredLayout);
162→
163→  return `${mermaidPart}--- layout ---\n${filteredSection}`;
164→}
165→
166→/**
167→ * Filter component definitions to only those that have instances on the canvas.
168→ */
169→export function filterUsedDefinitions(
170→  nodes: FlowNode[],
171→  definitions: ComponentDefinition[]
172→): ComponentDefinition[] {
173→  const usedDefIds = new Set(
174→    nodes
175→      .filter((n) => n.type === "componentInstance" && n.data.componentDefinitionId)
176→      .map((n) => n.data.componentDefinitionId as string)
177→  );
178→  return definitions.filter((d) => usedDefIds.has(d.id));
179→}
