 33→export function deserialize(content: string): DeserializeResult {
 34→  const layoutMatch = content.indexOf("--- layout ---");
 35→  if (layoutMatch === -1) {
 36→    throw new Error("Invalid .flowmaid file: missing layout section");
 37→  }
 38→
 39→  const layoutYaml = content.slice(layoutMatch + "--- layout ---".length).trim();
 40→  const layout: FlowmaidLayout = parse(layoutYaml);
 41→
 42→  const nodes: FlowNode[] = [];
 43→  let maxCounter = -1;
 44→
 45→  for (const [id, n] of Object.entries(layout.nodes)) {
 46→    const isComponentInstance = !!n.componentDefinitionId;
 47→    const type = n.isSubgraphGroup
 48→      ? "subgraphGroup"
 49→      : (isComponentInstance ? "componentInstance" : n.shape);
 50→    const node: FlowNode = {
 51→      id,
 52→      type,
 53→      position: n.position,
 54→      data: {
 55→        label: n.label,
 56→        shape: n.shape as FlowNode["data"]["shape"],
 57→      },
 58→      style: n.size ? { width: n.size.width, height: n.size.height } : undefined,
 59→    };
 60→
 61→    // Restore component instance fields
 62→    if (n.componentDefinitionId) node.data.componentDefinitionId = n.componentDefinitionId;
 63→    if (n.componentInstanceName) node.data.componentInstanceName = n.componentInstanceName;
 64→    if (n.componentSyncVersion !== undefined) node.data.componentSyncVersion = n.componentSyncVersion;
 65→    // componentLabelOverrides is deprecated — ignored on import
 66→    if (n.collapsed) node.data.collapsed = n.collapsed;
 67→    if (n.expandedSize) node.data.expandedSize = n.expandedSize;
 68→
 69→    // Restore style properties
 70→    if (n.fillColor) node.data.fillColor = n.fillColor;
 71→    if (n.fillOpacity !== undefined) node.data.fillOpacity = n.fillOpacity;
 72→    if (n.fillLightness !== undefined) node.data.fillLightness = n.fillLightness;
 73→    if (n.borderColor) node.data.borderColor = n.borderColor;
 74→    if (n.borderOpacity !== undefined) node.data.borderOpacity = n.borderOpacity;
 75→    if (n.borderLightness !== undefined) node.data.borderLightness = n.borderLightness;
 76→    if (n.borderWidth) node.data.borderWidth = n.borderWidth;
 77→    if (n.borderStyle) node.data.borderStyle = n.borderStyle;
 78→    if (n.zIndex !== undefined) node.zIndex = n.zIndex;
 79→    if (n.fontSize) node.data.fontSize = n.fontSize;
 80→    if (n.textColor) node.data.textColor = n.textColor;
 81→    if (n.textOpacity !== undefined) node.data.textOpacity = n.textOpacity;
 82→    if (n.textLightness !== undefined) node.data.textLightness = n.textLightness;
 83→    if (n.textAlign) node.data.textAlign = n.textAlign;
 84→    if (n.textVerticalAlign) node.data.textVerticalAlign = n.textVerticalAlign;
 85→    if (n.bold) node.data.bold = n.bold;
 86→    if (n.italic) node.data.italic = n.italic;
 87→    if (n.underline) node.data.underline = n.underline;
 88→    if (n.isSubgraphGroup) node.data.isSubgraphGroup = true;
 89→    if (n.subgraphParentId) {
 90→      node.parentId = n.subgraphParentId;
 91→      node.data.subgraphParentId = n.subgraphParentId;
 92→    }
 93→
 94→    nodes.push(node);
 95→
 96→    // Track highest counter for auto-id
 97→    if (/^[A-Z]+$/.test(id)) {
 98→      const counter = idToCounter(id);
 99→      if (counter > maxCounter) maxCounter = counter;
100→    }
101→  }
102→
103→  const edges: FlowEdge[] = [];
104→  for (const [id, e] of Object.entries(layout.edges)) {
105→    const edge: FlowEdge = {
106→      id,
107→      source: e.source,
108→      target: e.target,
109→      type: "labeled",
110→      sourceHandle: e.sourceHandle,
111→      targetHandle: e.targetHandle,
112→      data: {
113→        label: e.label ?? "",
114→        edgeType: e.edgeType ?? "bezier",
115→        markerStart: e.markerStart,
116→        markerEnd: e.markerEnd ?? "arrowclosed",
117→        strokeWidth: e.strokeWidth,
118→        strokeColor: e.strokeColor,
119→        strokeOpacity: e.strokeOpacity,
120→        strokeLightness: e.strokeLightness,
121→        strokeStyle: e.strokeStyle,
122→        waypoints: e.waypoints,
123→      },
124→    };
125→
126→    edges.push(edge);
127→  }
128→
129→  // Regenerate child nodes and internal edges for component instances
130→  const componentDefinitions = layout.componentDefinitions ?? [];
131→
132→  const allChildNodes: FlowNode[] = [];
133→  const allChildEdges: FlowEdge[] = [];
134→
135→  for (const node of nodes) {
136→    if (!node.data.componentDefinitionId) continue;
137→    const def = componentDefinitions.find((d) => d.id === node.data.componentDefinitionId);
138→    if (!def) continue;
139→
140→    // Populate runtime-only direction field from definition
141→    if (def.direction) {
142→      node.data.componentDefinitionDirection = def.direction;
143→    }
144→
145→    const isCollapsed = node.data.collapsed ?? false;
146→
147→    const { childNodes, childEdges } = generateComponentChildren({
148→      parentId: node.id,
149→      def,
150→      hidden: isCollapsed,
151→    });
152→
153→    allChildNodes.push(...childNodes);
154→    allChildEdges.push(...childEdges);
155→  }
156→
157→  // Generate bridge edges for component instances
158→  const allNodes = [...nodes, ...allChildNodes];
159→  const allEdgesBeforeBridge = [...edges, ...allChildEdges];
160→  const bridgeEdges: FlowEdge[] = [];
161→
162→  for (const node of nodes) {
163→    if (!node.data.componentDefinitionId) continue;
164→    const def = componentDefinitions.find((d) => d.id === node.data.componentDefinitionId);
165→    if (!def) continue;
166→
167→    const bridges = generateBridgeEdges({
168→      parentId: node.id,
169→      def,
170→      allEdges: allEdgesBeforeBridge,
171→      direction: def.direction ?? layout.direction,
172→    });
173→
174→    const isCollapsed = node.data.collapsed ?? false;
175→    for (const b of bridges) {
176→      if (isCollapsed) b.hidden = true;
177→      bridgeEdges.push(b);
178→    }
179→  }
180→
181→  return {
182→    nodes: allNodes,
183→    edges: [...allEdgesBeforeBridge, ...bridgeEdges],
184→    direction: layout.direction ?? "TD",
185→    nextIdCounter: maxCounter + 1,
186→    componentDefinitions,
187→  };
188→}
