  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { FlowDirection, ComponentDefinition } from "@/types/flow";
  3→import { nodeToMermaid } from "./nodeToMermaid";
  4→import { escapeMermaid } from "./nodeToMermaid";
  5→import { edgeToMermaid } from "./edgeToMermaid";
  6→
  7→/**
  8→ * Generate complete Mermaid flowchart syntax from nodes, edges, and direction
  9→ */
 10→export function generateMermaid(
 11→  nodes: FlowNode[],
 12→  edges: FlowEdge[],
 13→  direction: FlowDirection,
 14→  definitions?: ComponentDefinition[]
 15→): string {
 16→  const lines: string[] = [`flowchart ${direction}`];
 17→
 18→  // Build map of component instance IDs to their child nodes
 19→  const instanceChildMap = new Map<string, FlowNode[]>();
 20→  const childNodeIds = new Set<string>();
 21→  for (const node of nodes) {
 22→    if (node.data.componentParentId) {
 23→      const parentId = node.data.componentParentId as string;
 24→      if (!instanceChildMap.has(parentId)) instanceChildMap.set(parentId, []);
 25→      instanceChildMap.get(parentId)!.push(node);
 26→      childNodeIds.add(node.id);
 27→    }
 28→  }
 29→
 30→  // Build set of subgraph child node IDs
 31→  const subgraphChildIds = new Set<string>();
 32→  for (const node of nodes) {
 33→    if (node.data.subgraphParentId) {
 34→      subgraphChildIds.add(node.id);
 35→    }
 36→  }
 37→
 38→  for (const node of nodes) {
 39→    if (node.data.shape === "text") continue;
 40→    // Skip component children (they're handled within their parent's subgraph)
 41→    if (node.data.componentParentId) continue;
 42→    // Skip subgraph children (they're handled within their parent's subgraph block)
 43→    if (node.data.subgraphParentId) continue;
 44→
 45→    // Subgraph group: output as subgraph block with child nodes
 46→    if (node.data.isSubgraphGroup) {
 47→      const sgLabel = escapeMermaid(node.data.label);
 48→      lines.push(`    subgraph ${node.id}[${sgLabel}]`);
 49→      // Output child nodes
 50→      const children = nodes.filter((n) => n.data.subgraphParentId === node.id);
 51→      for (const child of children) {
 52→        if (child.data.shape === "text") continue;
 53→        // Nested subgraph group
 54→        if (child.data.isSubgraphGroup) {
 55→          lines.push(`    subgraph ${child.id}[${escapeMermaid(child.data.label)}]`);
 56→          const innerChildren = nodes.filter((n) => n.data.subgraphParentId === child.id);
 57→          for (const ic of innerChildren) {
 58→            if (ic.data.shape === "text") continue;
 59→            lines.push(nodeToMermaid(ic));
 60→          }
 61→          // Inner edges
 62→          const innerChildIds = new Set(innerChildren.map((n) => n.id));
 63→          for (const edge of edges) {
 64→            if (edge.data?.isBridgeEdge) continue;
 65→            if (innerChildIds.has(edge.source) && innerChildIds.has(edge.target)) {
 66→              lines.push(edgeToMermaid(edge));
 67→            }
 68→          }
 69→          lines.push(`    end`);
 70→          continue;
 71→        }
 72→        lines.push(nodeToMermaid(child));
 73→      }
 74→      // Output edges between direct children of this subgraph (excluding nested subgraph internals)
 75→      const directChildIds = new Set(children.filter((n) => !n.data.isSubgraphGroup).map((n) => n.id));
 76→      // Also include nested subgraph children for cross-group edges within this subgraph
 77→      const allDescendantIds = new Set<string>();
 78→      for (const child of children) {
 79→        allDescendantIds.add(child.id);
 80→        if (child.data.isSubgraphGroup) {
 81→          for (const n of nodes) {
 82→            if (n.data.subgraphParentId === child.id) allDescendantIds.add(n.id);
 83→          }
 84→        }
 85→      }
 86→      for (const edge of edges) {
 87→        if (edge.data?.isBridgeEdge) continue;
 88→        if (allDescendantIds.has(edge.source) && allDescendantIds.has(edge.target)) {
 89→          // Skip edges already output in nested subgraph blocks
 90→          const srcParent = nodes.find((n) => n.id === edge.source)?.data.subgraphParentId;
 91→          const tgtParent = nodes.find((n) => n.id === edge.target)?.data.subgraphParentId;
 92→          if (srcParent && tgtParent && srcParent === tgtParent && srcParent !== node.id) continue;
 93→          lines.push(edgeToMermaid(edge));
 94→        }
 95→      }
 96→      lines.push(`    end`);
 97→      continue;
 98→    }
 99→
100→    // Component instance: expand as subgraph using definition (including Start/End)
101→    if (node.type === "componentInstance" && node.data.componentDefinitionId) {
102→      const instanceLabel = escapeMermaid(node.data.componentInstanceName as string ?? node.data.label);
103→      lines.push(`    subgraph ${node.id}[${instanceLabel}]`);
104→
105→      // Get definition to include all nodes (including entry/exit which are excluded from canvas)
106→      const def = definitions?.find((d) => d.id === node.data.componentDefinitionId);
107→      if (def) {
108→        // Output all nodes from definition (including Start/End)
109→        for (const defNode of def.nodes) {
110→          const childId = `${node.id}_${defNode.id}`;
111→          const label = escapeMermaid(defNode.label);
112→          const shape = defNode.shape;
113→          let nodeLine: string;
114→          switch (shape) {
115→            case "diamond":
116→              nodeLine = `    ${childId}{${label}}`;
117→              break;
118→            case "roundedRect":
119→              nodeLine = `    ${childId}(${label})`;
120→              break;
121→            case "circle":
122→              nodeLine = `    ${childId}((${label}))`;
123→              break;
124→            case "stadium":
125→              nodeLine = `    ${childId}([${label}])`;
126→              break;
127→            default:
128→              nodeLine = `    ${childId}[${label}]`;
129→          }
130→          lines.push(nodeLine);
131→        }
132→
133→        // Output all internal edges from definition (including Start/End edges)
134→        for (const defEdge of def.edges) {
135→          const srcId = `${node.id}_${defEdge.source}`;
136→          const tgtId = `${node.id}_${defEdge.target}`;
137→          const label = defEdge.label;
138→          if (label) {
139→            lines.push(`    ${srcId} -->|${escapeMermaid(label)}| ${tgtId}`);
140→          } else {
141→            lines.push(`    ${srcId} --> ${tgtId}`);
142→          }
143→        }
144→      } else {
145→        // Fallback: use actual child nodes if definition not found
146→        const children = instanceChildMap.get(node.id) ?? [];
147→        for (const child of children) {
148→          const label = escapeMermaid(child.data.label);
149→          const shape = child.data.shape;
150→          let nodeLine: string;
151→          switch (shape) {
152→            case "diamond":
153→              nodeLine = `    ${child.id}{${label}}`;
154→              break;
155→            case "roundedRect":
156→              nodeLine = `    ${child.id}(${label})`;
157→              break;
158→            case "circle":
159→              nodeLine = `    ${child.id}((${label}))`;
160→              break;
161→            case "stadium":
162→              nodeLine = `    ${child.id}([${label}])`;
163→              break;
164→            default:
165→              nodeLine = `    ${child.id}[${label}]`;
166→          }
167→          lines.push(nodeLine);
168→        }
169→
170→        for (const edge of edges) {
171→          if (childNodeIds.has(edge.source) && childNodeIds.has(edge.target)) {
172→            const srcNode = nodes.find((n) => n.id === edge.source);
173→            const tgtNode = nodes.find((n) => n.id === edge.target);
174→            if (srcNode?.data.componentParentId === node.id && tgtNode?.data.componentParentId === node.id) {
175→              const label = edge.data?.label;
176→              if (label) {
177→                lines.push(`    ${edge.source} -->|${escapeMermaid(label)}| ${edge.target}`);
178→              } else {
179→                lines.push(`    ${edge.source} --> ${edge.target}`);
180→              }
181→            }
182→          }
183→        }
184→      }
185→
186→      lines.push(`    end`);
187→      continue;
188→    }
189→
190→    lines.push(nodeToMermaid(node));
191→  }
192→
193→  for (const edge of edges) {
194→    // Skip bridge edges
195→    if (edge.data?.isBridgeEdge) continue;
196→    // Skip internal edges (already handled in component subgraph)
197→    if (childNodeIds.has(edge.source) && childNodeIds.has(edge.target)) continue;
198→    // Skip edges between subgraph children (already handled in subgraph block)
199→    if (subgraphChildIds.has(edge.source) && subgraphChildIds.has(edge.target)) continue;
200→
201→    // For edges connected to component instances, remap to entry/exit child nodes
202→    if (definitions) {
203→      let source = edge.source;
204→      let target = edge.target;
205→
206→      const sourceNode = nodes.find((n) => n.id === source);
207→      const targetNode = nodes.find((n) => n.id === target);
208→
209→      if (sourceNode?.type === "componentInstance" && sourceNode.data.componentDefinitionId) {
210→        const def = definitions.find((d) => d.id === sourceNode.data.componentDefinitionId);
211→        if (def?.exitNodeId) {
212→          source = `${sourceNode.id}_${def.exitNodeId}`;
213→        }
214→      }
215→      if (targetNode?.type === "componentInstance" && targetNode.data.componentDefinitionId) {
216→        const def = definitions.find((d) => d.id === targetNode.data.componentDefinitionId);
217→        if (def?.entryNodeId) {
218→          target = `${targetNode.id}_${def.entryNodeId}`;
219→        }
220→      }
221→
222→      if (source !== edge.source || target !== edge.target) {
223→        const label = edge.data?.label;
224→        if (label) {
225→          lines.push(`    ${source} -->|${escapeMermaid(label)}| ${target}`);
226→        } else {
227→          lines.push(`    ${source} --> ${target}`);
228→        }
229→        continue;
230→      }
231→    }
232→
233→    lines.push(edgeToMermaid(edge));
234→  }
235→
236→  return lines.join("\n");
237→}
