  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { FlowDirection, NodeShape } from "@/types/flow";
  3→import { MarkerType } from "@xyflow/react";
  4→import {
  5→  DEFAULT_NODE_WIDTH,
  6→  DEFAULT_NODE_HEIGHT,
  7→  DEFAULT_DIAMOND_SIZE,
  8→} from "@/lib/constants";
  9→import { autoLayout } from "./autoLayout";
 10→import type { MermaidLayoutResult } from "./renderLayout";
 11→
 12→/**
 13→ * Reverse of escapeMermaid: convert Mermaid escape sequences back to original characters.
 14→ */
 15→export function unescapeMermaid(text: string): string {
 16→  return text
 17→    .replace(/#amp;/g, "&")
 18→    .replace(/#quot;/g, '"')
 19→    .replace(/#lt;/g, "<")
 20→    .replace(/#gt;/g, ">")
 21→    .replace(/#lbrace;/g, "{")
 22→    .replace(/#rbrace;/g, "}")
 23→    .replace(/#lpar;/g, "(")
 24→    .replace(/#rpar;/g, ")")
 25→    .replace(/#lbrack;/g, "[")
 26→    .replace(/#rbrack;/g, "]");
 27→}
 28→
 29→// Shape patterns ordered from most specific (longest delimiters) to least specific
 30→const SHAPE_PATTERNS: { open: string; close: string; shape: NodeShape }[] = [
 31→  { open: "((", close: "))", shape: "circle" },
 32→  { open: "([", close: "])", shape: "stadium" },
 33→  { open: "[(", close: ")]", shape: "cylinder" },
 34→  { open: "[[", close: "]]", shape: "predefinedProcess" },
 35→  { open: "{{", close: "}}", shape: "hexagon" },
 36→  { open: "[/", close: "\\]", shape: "document" },
 37→  { open: "[\\", close: "/]", shape: "manualInput" },
 38→  { open: "[/", close: "/]", shape: "parallelogram" },
 39→  { open: "[\\", close: "\\]", shape: "trapezoid" },
 40→  { open: "{", close: "}", shape: "diamond" },
 41→  { open: "(", close: ")", shape: "roundedRect" },
 42→  { open: "[", close: "]", shape: "rectangle" },
 43→];
 44→
 45→function parseNodeDef(raw: string): { id: string; label: string; shape: NodeShape } | null {
 46→  const trimmed = raw.trim();
 47→  if (!trimmed) return null;
 48→
 49→  for (const { open, close, shape } of SHAPE_PATTERNS) {
 50→    const openIdx = trimmed.indexOf(open);
 51→    if (openIdx < 1) continue;
 52→
 53→    const id = trimmed.slice(0, openIdx);
 54→    // Verify the rest ends with close
 55→    const rest = trimmed.slice(openIdx + open.length);
 56→    if (!rest.endsWith(close)) continue;
 57→
 58→    const label = unescapeMermaid(rest.slice(0, rest.length - close.length));
 59→    return { id, label, shape };
 60→  }
 61→
 62→  // No shape delimiters: just an ID reference
 63→  return null;
 64→}
 65→
 66→function getNodeSize(shape: NodeShape): { width: number; height: number } {
 67→  switch (shape) {
 68→    case "diamond":
 69→      return { width: DEFAULT_DIAMOND_SIZE, height: DEFAULT_DIAMOND_SIZE };
 70→    case "circle":
 71→      return { width: DEFAULT_NODE_HEIGHT * 2, height: DEFAULT_NODE_HEIGHT * 2 };
 72→    case "hexagon":
 73→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT + 10 };
 74→    case "cylinder":
 75→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 20 };
 76→    case "document":
 77→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 10 };
 78→    case "predefinedProcess":
 79→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 80→    case "display":
 81→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 82→    default:
 83→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT };
 84→  }
 85→}
 86→
 87→// Split an edge line by arrow patterns, returning segments and labels
 88→const ARROW_RE = /\s*-->\s*(?:\|([^|]*)\|)?\s*/;
 89→
 90→function splitEdgeLine(line: string): { segments: string[]; labels: string[] } | null {
 91→  const segments: string[] = [];
 92→  const labels: string[] = [];
 93→  let remaining = line;
 94→
 95→  while (true) {
 96→    const match = ARROW_RE.exec(remaining);
 97→    if (!match) {
 98→      segments.push(remaining.trim());
 99→      break;
100→    }
101→    segments.push(remaining.slice(0, match.index).trim());
102→    labels.push(match[1] ?? "");
103→    remaining = remaining.slice(match.index + match[0].length);
104→  }
105→
106→  if (segments.length < 2) return null;
107→  return { segments, labels };
108→}
109→
110→// Subgraph padding constants for bounding box calculation
111→const SUBGRAPH_PADDING_X = 40;
112→const SUBGRAPH_PADDING_Y_TOP = 40;
113→const SUBGRAPH_PADDING_Y_BOTTOM = 20;
114→
115→export function parseMermaid(text: string, edgeType?: import("@/types/flow").EdgeType, layout?: MermaidLayoutResult): {
116→  nodes: FlowNode[];
117→  edges: FlowEdge[];
118→  direction: FlowDirection;
119→  nextIdCounter: number;
120→} {
121→  const lines = text.split("\n").map((l) => l.trim()).filter((l) => l.length > 0);
122→  if (lines.length === 0) throw new Error("Empty input");
123→
124→  // Parse direction from first line
125→  const headerMatch = lines[0].match(/^(?:graph|flowchart)\s+(TD|LR|TB|BT)$/i);
126→  if (!headerMatch) throw new Error("Invalid header: expected 'graph TD|LR' or 'flowchart TD|LR'");
127→
128→  let direction: FlowDirection = "TD";
129→  const dirStr = headerMatch[1].toUpperCase();
130→  if (dirStr === "LR") direction = "LR";
131→  // TB and BT both map to TD
132→
133→  // Collect node definitions and edges
134→  const nodeDefs = new Map<string, { label: string; shape: NodeShape }>();
135→  const edgeList: { source: string; target: string; label: string }[] = [];
136→
137→  function registerNode(id: string, label: string, shape: NodeShape) {
138→    // First definition wins for shape/label
139→    if (!nodeDefs.has(id)) {
140→      nodeDefs.set(id, { label, shape });
141→    }
142→  }
143→
144→  function ensureNode(id: string) {
145→    if (!nodeDefs.has(id)) {
146→      nodeDefs.set(id, { label: id, shape: "rectangle" });
147→    }
148→  }
149→
150→  function resolveNodeRef(segment: string): string {
151→    const parsed = parseNodeDef(segment);
152→    if (parsed) {
153→      registerNode(parsed.id, parsed.label, parsed.shape);
154→      return parsed.id;
155→    }
156→    // Plain ID reference
157→    const id = segment.trim();
158→    ensureNode(id);
159→    return id;
160→  }
161→
162→  // Track subgraph contexts for subgraphGroup creation
163→  const subgraphStack: { id: string; label: string }[] = [];
164→  const subgraphLabels = new Map<string, string>();
165→  const nodeToSubgraph = new Map<string, string>();
166→  // Track parent subgraph for nested subgraphs
167→  const subgraphParentMap = new Map<string, string>();
168→
169→  for (let i = 1; i < lines.length; i++) {
170→    const line = lines[i];
171→
172→    // Check for subgraph start
173→    const subgraphMatch = line.match(/^subgraph\s+(\S+?)(?:\[([^\]]*)\])?\s*$/);
174→    if (subgraphMatch) {
175→      const sgId = subgraphMatch[1];
176→      const sgLabel = subgraphMatch[2] ? unescapeMermaid(subgraphMatch[2]) : sgId;
177→      // Track parent subgraph for nesting
178→      if (subgraphStack.length > 0) {
179→        subgraphParentMap.set(sgId, subgraphStack[subgraphStack.length - 1].id);
180→      }
181→      subgraphStack.push({ id: sgId, label: sgLabel });
182→      subgraphLabels.set(sgId, sgLabel);
183→      continue;
184→    }
185→
186→    // Check for end
187→    if (line === "end" && subgraphStack.length > 0) {
188→      subgraphStack.pop();
189→      continue;
190→    }
191→
192→    const currentSubgraph = subgraphStack.length > 0 ? subgraphStack[subgraphStack.length - 1].id : null;
193→
194→    // Try to parse as edge line (contains -->)
195→    const edgeParts = splitEdgeLine(line);
196→    if (edgeParts && edgeParts.segments.length >= 2) {
197→      const { segments, labels } = edgeParts;
198→      const resolvedIds = segments.map((s) => resolveNodeRef(s));
199→
200→      for (const rid of resolvedIds) {
201→        if (currentSubgraph && !nodeToSubgraph.has(rid)) {
202→          nodeToSubgraph.set(rid, currentSubgraph);
203→        }
204→      }
205→
206→      for (let j = 0; j < resolvedIds.length - 1; j++) {
207→        edgeList.push({
208→          source: resolvedIds[j],
209→          target: resolvedIds[j + 1],
210→          label: labels[j] ?? "",
211→        });
212→      }
213→      continue;
214→    }
215→
216→    // Try to parse as standalone node definition
217→    const parsed = parseNodeDef(line);
218→    if (parsed) {
219→      registerNode(parsed.id, parsed.label, parsed.shape);
220→      if (currentSubgraph && !nodeToSubgraph.has(parsed.id)) {
221→        nodeToSubgraph.set(parsed.id, currentSubgraph);
222→      }
223→    }
224→  }
225→
226→  // Layout: use mermaid.js layout if provided, otherwise fall back to autoLayout
227→  let positions: Map<string, { x: number; y: number }>;
228→  let backEdges: Set<string>;
229→  const sizeMap = new Map<string, { width: number; height: number }>();
230→
231→  if (layout) {
232→    // Use mermaid.js layout result
233→    positions = new Map<string, { x: number; y: number }>();
234→    backEdges = new Set<string>();
235→
236→    for (const [id, def] of nodeDefs) {
237→      const mNode = layout.nodes.get(id);
238→      if (mNode) {
239→        // mermaid.js returns center coordinates; convert to top-left
240→        positions.set(id, {
241→          x: mNode.x - mNode.width / 2,
242→          y: mNode.y - mNode.height / 2,
243→        });
244→        sizeMap.set(id, { width: mNode.width, height: mNode.height });
245→      } else {
246→        const size = getNodeSize(def.shape);
247→        positions.set(id, { x: 0, y: 0 });
248→        sizeMap.set(id, size);
249→      }
250→    }
251→  } else {
252→    // Fall back to autoLayout
253→    const nodeIds = [...nodeDefs.keys()].map((id) => ({ id }));
254→    for (const [id, def] of nodeDefs) {
255→      sizeMap.set(id, getNodeSize(def.shape));
256→    }
257→    const layoutResult = autoLayout(nodeIds, edgeList, direction, sizeMap);
258→    positions = layoutResult.positions;
259→    backEdges = layoutResult.backEdges;
260→  }
261→
262→  // Build FlowNode[]
263→  const nodes: FlowNode[] = [];
264→  let maxCounter = 0;
265→
266→  for (const [id, def] of nodeDefs) {
267→    const pos = positions.get(id) ?? { x: 0, y: 0 };
268→    const size = sizeMap.get(id) ?? getNodeSize(def.shape);
269→
270→    // Track highest alphabetic ID counter
271→    if (/^[A-Z]+$/.test(id)) {
272→      let counter = 0;
273→      for (let c = 0; c < id.length; c++) {
274→        counter = counter * 26 + (id.charCodeAt(c) - 64);
275→      }
276→      counter -= 1;
277→      if (counter + 1 > maxCounter) maxCounter = counter + 1;
278→    }
279→
280→    nodes.push({
281→      id,
282→      type: def.shape,
283→      position: pos,
284→      data: { label: def.label, shape: def.shape },
285→      style: { width: size.width, height: size.height },
286→    });
287→  }
288→
289→  // Handle directions: forward edges follow main axis, back-edges loop via cross axis
290→  const fwdSourceHandle = direction === "LR" ? "right-source" : "bottom-source";
291→  const fwdTargetHandle = direction === "LR" ? "left-target" : "top-target";
292→  const backSourceHandle = direction === "LR" ? "bottom-source" : "right-source";
293→  const backTargetHandle = direction === "LR" ? "bottom-target" : "right-target";
294→
295→  // Build FlowEdge[]
296→  const edges: FlowEdge[] = [];
297→  for (const e of edgeList) {
298→    const isBack = backEdges.has(`${e.source}->${e.target}`);
299→    const sh = isBack ? backSourceHandle : fwdSourceHandle;
300→    const th = isBack ? backTargetHandle : fwdTargetHandle;
301→    const edgeId = `${e.source}-${e.target}-${sh}-${th}`;
302→    edges.push({
303→      id: edgeId,
304→      source: e.source,
305→      target: e.target,
306→      sourceHandle: sh,
307→      targetHandle: th,
308→      type: "labeled",
309→      markerEnd: { type: MarkerType.ArrowClosed },
310→      data: {
311→        label: e.label,
312→        edgeType: edgeType ?? "bezier",
313→        markerEnd: "arrowclosed",
314→      },
315→    });
316→  }
317→
318→  // Convert subgraphs to subgraphGroup nodes with child parentId relationships
319→  // Store absolute positions of each subgraph for coordinate conversion
320→  const sgAbsPositions = new Map<string, { x: number; y: number }>();
321→
322→  // Process subgraphs: topological order (outermost first)
323→  // Build processing order: subgraphs without parents first, then their children
324→  const sgProcessOrder: string[] = [];
325→  const sgProcessed = new Set<string>();
326→  const enqueueSg = (sgId: string) => {
327→    if (sgProcessed.has(sgId)) return;
328→    const parentSgId = subgraphParentMap.get(sgId);
329→    if (parentSgId && !sgProcessed.has(parentSgId)) enqueueSg(parentSgId);
330→    sgProcessed.add(sgId);
331→    sgProcessOrder.push(sgId);
332→  };
333→  for (const sgId of subgraphLabels.keys()) enqueueSg(sgId);
334→
335→  for (const sgId of sgProcessOrder) {
336→    const sgLabel = subgraphLabels.get(sgId)!;
337→
338→    // Collect direct child node IDs for this subgraph
339→    const childNodeIds = new Set<string>();
340→    for (const [nodeId, parentSgId] of nodeToSubgraph) {
341→      if (parentSgId === sgId) childNodeIds.add(nodeId);
342→    }
343→
344→    // Get direct child nodes (regular nodes only, not nested subgraph groups)
345→    const childNodes = nodes.filter((n) => childNodeIds.has(n.id));
346→
347→    // Also include nested subgraph group nodes whose parent is this subgraph
348→    const nestedSgIds: string[] = [];
349→    for (const [nestedSgId, parentSgId] of subgraphParentMap) {
350→      if (parentSgId === sgId) nestedSgIds.push(nestedSgId);
351→    }
352→
353→    // Compute absolute position and size of this subgraph
354→    let sgAbsPos: { x: number; y: number };
355→    let sgSize: { width: number; height: number };
356→
357→    const sgLayout = layout?.subgraphs.get(sgId);
358→    if (sgLayout) {
359→      sgAbsPos = { x: sgLayout.x, y: sgLayout.y };
360→      sgSize = { width: sgLayout.width, height: sgLayout.height };
361→    } else {
362→      // Compute bounding box from child positions (all absolute at this point)
363→      let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
364→      // Include regular child nodes
365→      for (const child of childNodes) {
366→        const w = (child.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
367→        const h = (child.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
368→        if (child.position.x < minX) minX = child.position.x;
369→        if (child.position.y < minY) minY = child.position.y;
370→        if (child.position.x + w > maxX) maxX = child.position.x + w;
371→        if (child.position.y + h > maxY) maxY = child.position.y + h;
372→      }
373→      // Include nested subgraph groups
374→      for (const nestedSgId of nestedSgIds) {
375→        const nestedAbsPos = sgAbsPositions.get(nestedSgId);
376→        const nestedNode = nodes.find((n) => n.id === nestedSgId);
377→        if (nestedAbsPos && nestedNode) {
378→          const w = (nestedNode.style as Record<string, number>)?.width ?? 200;
379→          const h = (nestedNode.style as Record<string, number>)?.height ?? 100;
380→          if (nestedAbsPos.x < minX) minX = nestedAbsPos.x;
381→          if (nestedAbsPos.y < minY) minY = nestedAbsPos.y;
382→          if (nestedAbsPos.x + w > maxX) maxX = nestedAbsPos.x + w;
383→          if (nestedAbsPos.y + h > maxY) maxY = nestedAbsPos.y + h;
384→        }
385→      }
386→
387→      if (minX === Infinity) {
388→        // Empty subgraph
389→        sgAbsPos = { x: 0, y: 0 };
390→        sgSize = { width: 200, height: 100 };
391→      } else {
392→        sgAbsPos = {
393→          x: minX - SUBGRAPH_PADDING_X,
394→          y: minY - SUBGRAPH_PADDING_Y_TOP,
395→        };
396→        sgSize = {
397→          width: (maxX - minX) + SUBGRAPH_PADDING_X * 2,
398→          height: (maxY - minY) + SUBGRAPH_PADDING_Y_TOP + SUBGRAPH_PADDING_Y_BOTTOM,
399→        };
400→      }
401→    }
402→
403→    sgAbsPositions.set(sgId, sgAbsPos);
404→
405→    // Determine the position for the subgraph group node
406→    const parentSgId = subgraphParentMap.get(sgId);
407→    let sgNodePos: { x: number; y: number };
408→    if (parentSgId) {
409→      // Relative to parent subgraph's absolute position
410→      const parentAbsPos = sgAbsPositions.get(parentSgId)!;
411→      sgNodePos = {
412→        x: sgAbsPos.x - parentAbsPos.x,
413→        y: sgAbsPos.y - parentAbsPos.y,
414→      };
415→    } else {
416→      sgNodePos = sgAbsPos;
417→    }
418→
419→    // Create subgraphGroup node
420→    const sgNode: FlowNode = {
421→      id: sgId,
422→      type: "subgraphGroup",
423→      position: sgNodePos,
424→      data: { label: sgLabel, shape: "rectangle" as NodeShape, isSubgraphGroup: true },
425→      style: { width: sgSize.width, height: sgSize.height },
426→      zIndex: -1,
427→    };
428→
429→    if (parentSgId) {
430→      sgNode.parentId = parentSgId;
431→      sgNode.data.subgraphParentId = parentSgId;
432→    }
433→
434→    nodes.push(sgNode);
435→
436→    // Convert child nodes: set parentId and convert to relative coordinates
437→    for (const child of childNodes) {
438→      child.parentId = sgId;
439→      child.data = { ...child.data, subgraphParentId: sgId };
440→      child.position = {
441→        x: child.position.x - sgAbsPos.x,
442→        y: child.position.y - sgAbsPos.y,
443→      };
444→    }
445→
446→    // Convert nested subgraph group nodes' positions to relative
447→    for (const nestedSgId of nestedSgIds) {
448→      const nestedNode = nodes.find((n) => n.id === nestedSgId);
449→      if (nestedNode) {
450→        const nestedAbsPos = sgAbsPositions.get(nestedSgId)!;
451→        nestedNode.position = {
452→          x: nestedAbsPos.x - sgAbsPos.x,
453→          y: nestedAbsPos.y - sgAbsPos.y,
454→        };
455→      }
456→    }
457→  }
458→
459→  return {
460→    nodes,
461→    edges,
462→    direction,
463→    nextIdCounter: maxCounter,
464→  };
465→}
