  1→/**
  2→ * Render Mermaid text using mermaid.js and extract node/subgraph positions and sizes from the SVG output.
  3→ */
  4→
  5→export interface MermaidNodeLayout {
  6→  id: string;
  7→  x: number;       // center X
  8→  y: number;       // center Y
  9→  width: number;
 10→  height: number;
 11→}
 12→
 13→export interface MermaidSubgraphLayout {
 14→  id: string;
 15→  x: number;       // top-left X
 16→  y: number;       // top-left Y
 17→  width: number;
 18→  height: number;
 19→}
 20→
 21→export interface MermaidLayoutResult {
 22→  nodes: Map<string, MermaidNodeLayout>;
 23→  subgraphs: Map<string, MermaidSubgraphLayout>;
 24→}
 25→
 26→const CONTAINER_ID = "mermaid-layout-tmp";
 27→
 28→/**
 29→ * Strip mermaid's ID decorations to recover the original node/subgraph ID.
 30→ * mermaid.js generates IDs like "flowchart-A-0" for node "A".
 31→ */
 32→function extractId(rawId: string): string {
 33→  // Pattern: "flowchart-{id}-{number}" or just the id with prefix
 34→  const match = rawId.match(/^flowchart-(.+?)-\d+$/);
 35→  if (match) return match[1];
 36→  // Fallback: return as-is
 37→  return rawId;
 38→}
 39→
 40→export async function renderMermaidLayout(
 41→  mermaidText: string,
 42→): Promise<MermaidLayoutResult> {
 43→  const mermaid = (await import("mermaid")).default;
 44→  mermaid.initialize({
 45→    startOnLoad: false,
 46→    securityLevel: "loose",
 47→    flowchart: {
 48→      htmlLabels: false,  // SVG labels for accurate size measurement
 49→    },
 50→  });
 51→
 52→  // Create off-screen container
 53→  const container = document.createElement("div");
 54→  container.style.position = "absolute";
 55→  container.style.left = "-9999px";
 56→  container.style.top = "-9999px";
 57→  document.body.appendChild(container);
 58→
 59→  try {
 60→    const { svg } = await mermaid.render(CONTAINER_ID, mermaidText);
 61→    container.innerHTML = svg;
 62→    const svgEl = container.querySelector("svg");
 63→    if (!svgEl) throw new Error("Failed to render Mermaid SVG");
 64→
 65→    const nodes = new Map<string, MermaidNodeLayout>();
 66→    const subgraphs = new Map<string, MermaidSubgraphLayout>();
 67→
 68→    // Extract node positions and sizes from .node elements
 69→    svgEl.querySelectorAll(".node").forEach((el) => {
 70→      const gEl = el as SVGGraphicsElement;
 71→      const rawId = gEl.id;
 72→      if (!rawId) return;
 73→      const id = extractId(rawId);
 74→
 75→      const bbox = gEl.getBBox();
 76→      // Get transform to compute absolute position
 77→      const transform = gEl.getAttribute("transform");
 78→      let tx = 0;
 79→      let ty = 0;
 80→      if (transform) {
 81→        const translateMatch = transform.match(/translate\(\s*([\d.-]+)\s*,?\s*([\d.-]+)\s*\)/);
 82→        if (translateMatch) {
 83→          tx = parseFloat(translateMatch[1]);
 84→          ty = parseFloat(translateMatch[2]);
 85→        }
 86→      }
 87→
 88→      nodes.set(id, {
 89→        id,
 90→        x: tx,
 91→        y: ty,
 92→        width: bbox.width,
 93→        height: bbox.height,
 94→      });
 95→    });
 96→
 97→    // Extract subgraph (cluster) positions and sizes
 98→    svgEl.querySelectorAll(".cluster").forEach((el) => {
 99→      const gEl = el as SVGGraphicsElement;
100→      const rawId = gEl.id;
101→      if (!rawId) return;
102→      const id = extractId(rawId);
103→
104→      const rect = gEl.querySelector("rect");
105→      if (!rect) return;
106→
107→      const x = parseFloat(rect.getAttribute("x") ?? "0");
108→      const y = parseFloat(rect.getAttribute("y") ?? "0");
109→      const width = parseFloat(rect.getAttribute("width") ?? "0");
110→      const height = parseFloat(rect.getAttribute("height") ?? "0");
111→
112→      // Account for parent group transform
113→      const transform = gEl.getAttribute("transform");
114→      let tx = 0;
115→      let ty = 0;
116→      if (transform) {
117→        const translateMatch = transform.match(/translate\(\s*([\d.-]+)\s*,?\s*([\d.-]+)\s*\)/);
118→        if (translateMatch) {
119→          tx = parseFloat(translateMatch[1]);
120→          ty = parseFloat(translateMatch[2]);
121→        }
122→      }
123→
124→      subgraphs.set(id, {
125→        id,
126→        x: x + tx,
127→        y: y + ty,
128→        width,
129→        height,
130→      });
131→    });
132→
133→    return { nodes, subgraphs };
134→  } finally {
135→    document.body.removeChild(container);
136→  }
137→}
