 12→export function serialize(
 13→  nodes: FlowNode[],
 14→  edges: FlowEdge[],
 15→  direction: FlowDirection,
 16→  componentDefinitions?: ComponentDefinition[],
 17→  options?: SerializeOptions
 18→): string {
 19→  const { includeUnusedDefinitions = true } = options ?? {};
 20→
 21→  // Filter to only definitions that have instances on the canvas
 22→  const usedDefinitions = componentDefinitions && !includeUnusedDefinitions
 23→    ? filterUsedDefinitions(nodes, componentDefinitions)
 24→    : componentDefinitions;
 25→
 26→  const mermaidSection = generateMermaid(nodes, edges, direction, usedDefinitions);
 27→
 28→  const nodesLayout: Record<string, FlowmaidNodeLayout> = {};
 29→  for (const node of nodes) {
 30→    // Skip component child nodes (they're regenerated from definition)
 31→    // Note: subgraphGroup child nodes (subgraphParentId) are NOT skipped — they're serialized individually
 32→    if (node.data.componentParentId) continue;
 33→    const styleW = (node.style as Record<string, unknown>)?.width as number | undefined;
 34→    const styleH = (node.style as Record<string, unknown>)?.height as number | undefined;
 35→    const w = node.width ?? styleW;
 36→    const h = node.height ?? styleH;
 37→
 38→    const entry: FlowmaidNodeLayout = {
 39→      position: { x: node.position.x, y: node.position.y },
 40→      size: w && h ? { width: w, height: h } : undefined,
 41→      shape: node.data.shape,
 42→      label: node.data.label,
 43→    };
 44→    if (node.data.fillColor) entry.fillColor = node.data.fillColor;
 45→    if (node.data.fillOpacity !== undefined && node.data.fillOpacity !== 10) entry.fillOpacity = node.data.fillOpacity;
 46→    if (node.data.fillLightness !== undefined && node.data.fillLightness !== 5) entry.fillLightness = node.data.fillLightness;
 47→    if (node.data.borderColor) entry.borderColor = node.data.borderColor;
 48→    if (node.data.borderOpacity !== undefined && node.data.borderOpacity !== 10) entry.borderOpacity = node.data.borderOpacity;
 49→    if (node.data.borderLightness !== undefined && node.data.borderLightness !== 5) entry.borderLightness = node.data.borderLightness;
 50→    if (node.data.borderWidth) entry.borderWidth = node.data.borderWidth;
 51→    if (node.data.borderStyle) entry.borderStyle = node.data.borderStyle;
 52→    if (node.zIndex !== undefined && node.zIndex !== 0) entry.zIndex = node.zIndex;
 53→    if (node.data.fontSize) entry.fontSize = node.data.fontSize;
 54→    if (node.data.textColor) entry.textColor = node.data.textColor;
 55→    if (node.data.textOpacity !== undefined && node.data.textOpacity !== 10) entry.textOpacity = node.data.textOpacity;
 56→    if (node.data.textLightness !== undefined && node.data.textLightness !== 5) entry.textLightness = node.data.textLightness;
 57→    if (node.data.textAlign && node.data.textAlign !== "center") entry.textAlign = node.data.textAlign;
 58→    if (node.data.textVerticalAlign && node.data.textVerticalAlign !== "middle") entry.textVerticalAlign = node.data.textVerticalAlign;
 59→    if (node.data.bold) entry.bold = node.data.bold;
 60→    if (node.data.italic) entry.italic = node.data.italic;
 61→    if (node.data.underline) entry.underline = node.data.underline;
 62→    if (node.data.componentDefinitionId) entry.componentDefinitionId = node.data.componentDefinitionId as string;
 63→    if (node.data.componentInstanceName) entry.componentInstanceName = node.data.componentInstanceName as string;
 64→    if (node.data.componentSyncVersion !== undefined) entry.componentSyncVersion = node.data.componentSyncVersion as number;
 65→    if (node.data.collapsed) entry.collapsed = true;
 66→    if (node.data.expandedSize) entry.expandedSize = node.data.expandedSize as { width: number; height: number };
 67→    if (node.data.isSubgraphGroup) entry.isSubgraphGroup = true;
 68→    if (node.data.subgraphParentId) entry.subgraphParentId = node.data.subgraphParentId as string;
 69→
 70→    nodesLayout[node.id] = entry;
 71→  }
 72→
 73→  // Build set of component child node IDs to filter internal edges
 74→  const componentChildIds = new Set(nodes.filter((n) => n.data.componentParentId).map((n) => n.id));
 75→
 76→  const edgesLayout: Record<string, FlowmaidEdgeLayout> = {};
 77→  for (const edge of edges) {
 78→    // Skip bridge edges
 79→    if (edge.data?.isBridgeEdge) continue;
 80→    // Skip internal edges between component children
 81→    if (componentChildIds.has(edge.source) && componentChildIds.has(edge.target)) continue;
 82→    const entry: FlowmaidEdgeLayout = {
 83→      source: edge.source,
 84→      target: edge.target,
 85→    };
 86→    if (edge.data?.label) entry.label = edge.data.label;
 87→    if (edge.sourceHandle) entry.sourceHandle = edge.sourceHandle;
 88→    if (edge.targetHandle) entry.targetHandle = edge.targetHandle;
 89→    if (edge.data?.edgeType && edge.data.edgeType !== "bezier") entry.edgeType = edge.data.edgeType;
 90→    if (edge.data?.markerStart) entry.markerStart = edge.data.markerStart;
 91→    if (edge.data?.markerEnd && edge.data.markerEnd !== "arrowclosed") entry.markerEnd = edge.data.markerEnd;
 92→    if (edge.data?.strokeWidth && edge.data.strokeWidth !== 2) entry.strokeWidth = edge.data.strokeWidth;
 93→    if (edge.data?.strokeColor) entry.strokeColor = edge.data.strokeColor;
 94→    if (edge.data?.strokeOpacity !== undefined && edge.data.strokeOpacity !== 10) entry.strokeOpacity = edge.data.strokeOpacity;
 95→    if (edge.data?.strokeLightness !== undefined && edge.data.strokeLightness !== 5) entry.strokeLightness = edge.data.strokeLightness;
 96→    if (edge.data?.strokeStyle && edge.data.strokeStyle !== "solid") entry.strokeStyle = edge.data.strokeStyle;
 97→    if (edge.data?.waypoints && edge.data.waypoints.length > 0) entry.waypoints = edge.data.waypoints;
 98→
 99→    edgesLayout[edge.id] = entry;
100→  }
101→
102→  const layout: FlowmaidLayout = {
103→    direction,
104→    nodes: nodesLayout,
105→    edges: edgesLayout,
106→    ...(usedDefinitions && usedDefinitions.length > 0 && { componentDefinitions: usedDefinitions }),
107→  };
108→
109→  const layoutSection = stringify(layout);
110→
111→  return `--- mermaid ---\n${mermaidSection}\n\n--- layout ---\n${layoutSection}`;
112→}
