156→    }
157→  }
158→  if (layout.componentDefinitions) {
159→    filteredLayout.componentDefinitions = layout.componentDefinitions;
160→  }
161→
162→  const filteredSection = stringify(filteredLayout);
163→
164→  return `${mermaidPart}--- layout ---\n${filteredSection}`;
