 16→/**
 17→ * Parse a .flowmaid file and return only the raw layout data (no React Flow conversion).
 18→ * Used by diff comparison to compare layouts directly without React Flow internal state.
 19→ */
 20→export function parseLayoutOnly(content: string): FlowmaidLayout {
 21→  const layoutMatch = content.indexOf("--- layout ---");
 22→  if (layoutMatch === -1) {
 23→    throw new Error("Invalid .flowmaid file: missing layout section");
 24→  }
 25→  const layoutYaml = content.slice(layoutMatch + "--- layout ---".length).trim();
 26→  const layout = parse(layoutYaml) as FlowmaidLayout | null;
 27→  if (!layout) {
 28→    throw new Error("Invalid .flowmaid file: empty layout section");
 29→  }
 30→  return layout;
 31→}
