  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { FlowDirection, ComponentDefinition } from "@/types/flow";
  3→import { nodeToMermaid } from "./nodeToMermaid";
  4→import { escapeMermaid } from "./nodeToMermaid";
  5→import { edgeToMermaid } from "./edgeToMermaid";
  6→
  7→/**
  8→ * Recursively emit a subgraph block for a subgraphGroup node.
  9→ * Handles arbitrary nesting depth. Edges are output at the level where
 10→ * both source and target are direct children (not deeper descendants).
 11→ */
 12→function emitSubgraphBlock(
 13→  sgId: string,
 14→  sgLabel: string,
 15→  nodes: FlowNode[],
 16→  edges: FlowEdge[],
 17→  lines: string[],
 18→): void {
 19→  lines.push(`    subgraph ${sgId}[${escapeMermaid(sgLabel)}]`);
 20→
 21→  const children = nodes.filter((n) => n.data.subgraphParentId === sgId);
 22→  const directNonSgChildIds = new Set<string>();
 23→
 24→  for (const child of children) {
 25→    if (child.data.shape === "text") continue;
 26→    if (child.data.isSubgraphGroup) {
 27→      // Recurse into nested subgraph
 28→      emitSubgraphBlock(child.id, child.data.label, nodes, edges, lines);
 29→    } else {
 30→      lines.push(nodeToMermaid(child));
 31→      directNonSgChildIds.add(child.id);
 32→    }
 33→  }
 34→
 35→  // Output edges where both endpoints are direct non-subgraph children of this group
 36→  for (const edge of edges) {
 37→    if (edge.data?.isBridgeEdge) continue;
 38→    if (directNonSgChildIds.has(edge.source) && directNonSgChildIds.has(edge.target)) {
 39→      lines.push(edgeToMermaid(edge));
 40→    }
 41→  }
 42→
 43→  lines.push(`    end`);
 44→}
 45→
 46→/**
 47→ * Generate complete Mermaid flowchart syntax from nodes, edges, and direction
 48→ */
 49→export function generateMermaid(
 50→  nodes: FlowNode[],
 51→  edges: FlowEdge[],
 52→  direction: FlowDirection,
 53→  definitions?: ComponentDefinition[]
 54→): string {
 55→  const lines: string[] = [`flowchart ${direction}`];
 56→
 57→  // Build map of component instance IDs to their child nodes
 58→  const instanceChildMap = new Map<string, FlowNode[]>();
 59→  const childNodeIds = new Set<string>();
 60→  for (const node of nodes) {
 61→    if (node.data.componentParentId) {
 62→      const parentId = node.data.componentParentId as string;
 63→      if (!instanceChildMap.has(parentId)) instanceChildMap.set(parentId, []);
 64→      instanceChildMap.get(parentId)!.push(node);
 65→      childNodeIds.add(node.id);
 66→    }
 67→  }
 68→
 69→  // Build set of subgraph child node IDs
 70→  const subgraphChildIds = new Set<string>();
 71→  for (const node of nodes) {
 72→    if (node.data.subgraphParentId) {
 73→      subgraphChildIds.add(node.id);
 74→    }
 75→  }
 76→
 77→  for (const node of nodes) {
 78→    if (node.data.shape === "text") continue;
 79→    // Skip component children (they're handled within their parent's subgraph)
 80→    if (node.data.componentParentId) continue;
 81→    // Skip subgraph children (they're handled within their parent's subgraph block)
 82→    if (node.data.subgraphParentId) continue;
 83→
 84→    // Subgraph group: output as subgraph block with child nodes (recursive for nesting)
 85→    if (node.data.isSubgraphGroup) {
 86→      emitSubgraphBlock(node.id, node.data.label, nodes, edges, lines);
 87→      continue;
 88→    }
 89→
 90→    // Component instance: expand as subgraph using definition (including Start/End)
 91→    if (node.type === "componentInstance" && node.data.componentDefinitionId) {
 92→      const instanceLabel = escapeMermaid(node.data.componentInstanceName as string ?? node.data.label);
 93→      lines.push(`    subgraph ${node.id}[${instanceLabel}]`);
 94→
 95→      // Get definition to include all nodes (including entry/exit which are excluded from canvas)
 96→      const def = definitions?.find((d) => d.id === node.data.componentDefinitionId);
 97→      if (def) {
 98→        // Output all nodes from definition (including Start/End)
 99→        for (const defNode of def.nodes) {
100→          const childId = `${node.id}_${defNode.id}`;
101→          const label = escapeMermaid(defNode.label);
102→          const shape = defNode.shape;
103→          let nodeLine: string;
104→          switch (shape) {
105→            case "diamond":
106→              nodeLine = `    ${childId}{${label}}`;
107→              break;
108→            case "roundedRect":
109→              nodeLine = `    ${childId}(${label})`;
110→              break;
111→            case "circle":
112→              nodeLine = `    ${childId}((${label}))`;
113→              break;
114→            case "stadium":
115→              nodeLine = `    ${childId}([${label}])`;
116→              break;
117→            default:
118→              nodeLine = `    ${childId}[${label}]`;
119→          }
120→          lines.push(nodeLine);
121→        }
122→
123→        // Output all internal edges from definition (including Start/End edges)
124→        for (const defEdge of def.edges) {
125→          const srcId = `${node.id}_${defEdge.source}`;
126→          const tgtId = `${node.id}_${defEdge.target}`;
127→          const label = defEdge.label;
128→          if (label) {
129→            lines.push(`    ${srcId} -->|${escapeMermaid(label)}| ${tgtId}`);
130→          } else {
131→            lines.push(`    ${srcId} --> ${tgtId}`);
132→          }
133→        }
134→      } else {
135→        // Fallback: use actual child nodes if definition not found
136→        const children = instanceChildMap.get(node.id) ?? [];
137→        for (const child of children) {
138→          const label = escapeMermaid(child.data.label);
139→          const shape = child.data.shape;
140→          let nodeLine: string;
141→          switch (shape) {
142→            case "diamond":
143→              nodeLine = `    ${child.id}{${label}}`;
144→              break;
145→            case "roundedRect":
146→              nodeLine = `    ${child.id}(${label})`;
147→              break;
148→            case "circle":
149→              nodeLine = `    ${child.id}((${label}))`;
150→              break;
151→            case "stadium":
152→              nodeLine = `    ${child.id}([${label}])`;
153→              break;
154→            default:
155→              nodeLine = `    ${child.id}[${label}]`;
156→          }
157→          lines.push(nodeLine);
158→        }
159→
160→        for (const edge of edges) {
161→          if (childNodeIds.has(edge.source) && childNodeIds.has(edge.target)) {
162→            const srcNode = nodes.find((n) => n.id === edge.source);
163→            const tgtNode = nodes.find((n) => n.id === edge.target);
164→            if (srcNode?.data.componentParentId === node.id && tgtNode?.data.componentParentId === node.id) {
165→              const label = edge.data?.label;
166→              if (label) {
167→                lines.push(`    ${edge.source} -->|${escapeMermaid(label)}| ${edge.target}`);
168→              } else {
169→                lines.push(`    ${edge.source} --> ${edge.target}`);
170→              }
171→            }
172→          }
173→        }
174→      }
175→
176→      lines.push(`    end`);
177→      continue;
178→    }
179→
180→    lines.push(nodeToMermaid(node));
181→  }
182→
183→  for (const edge of edges) {
184→    // Skip bridge edges
185→    if (edge.data?.isBridgeEdge) continue;
186→    // Skip internal edges (already handled in component subgraph)
187→    if (childNodeIds.has(edge.source) && childNodeIds.has(edge.target)) continue;
188→    // Skip edges between subgraph children that share the same direct parent
189→    // (already handled in their subgraph block). Cross-subgraph edges are output here.
190→    if (subgraphChildIds.has(edge.source) && subgraphChildIds.has(edge.target)) {
191→      const srcNode = nodes.find((n) => n.id === edge.source);
192→      const tgtNode = nodes.find((n) => n.id === edge.target);
193→      const srcParent = srcNode?.data.subgraphParentId as string | undefined;
194→      const tgtParent = tgtNode?.data.subgraphParentId as string | undefined;
195→      if (srcParent && tgtParent && srcParent === tgtParent) continue;
196→    }
197→
198→    // For edges connected to component instances, remap to entry/exit child nodes
199→    if (definitions) {
200→      let source = edge.source;
201→      let target = edge.target;
202→
203→      const sourceNode = nodes.find((n) => n.id === source);
204→      const targetNode = nodes.find((n) => n.id === target);
205→
206→      if (sourceNode?.type === "componentInstance" && sourceNode.data.componentDefinitionId) {
207→        const def = definitions.find((d) => d.id === sourceNode.data.componentDefinitionId);
208→        if (def?.exitNodeId) {
209→          source = `${sourceNode.id}_${def.exitNodeId}`;
210→        }
211→      }
212→      if (targetNode?.type === "componentInstance" && targetNode.data.componentDefinitionId) {
213→        const def = definitions.find((d) => d.id === targetNode.data.componentDefinitionId);
214→        if (def?.entryNodeId) {
215→          target = `${targetNode.id}_${def.entryNodeId}`;
216→        }
217→      }
218→
219→      if (source !== edge.source || target !== edge.target) {
220→        const label = edge.data?.label;
221→        if (label) {
222→          lines.push(`    ${source} -->|${escapeMermaid(label)}| ${target}`);
223→        } else {
224→          lines.push(`    ${source} --> ${target}`);
225→        }
226→        continue;
227→      }
228→    }
229→
230→    lines.push(edgeToMermaid(edge));
231→  }
232→
233→  return lines.join("\n");
234→}
