  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { FlowDirection, NodeShape } from "@/types/flow";
  3→import { MarkerType } from "@xyflow/react";
  4→import {
  5→  DEFAULT_NODE_WIDTH,
  6→  DEFAULT_NODE_HEIGHT,
  7→  DEFAULT_DIAMOND_SIZE,
  8→} from "@/lib/constants";
  9→import { autoLayout } from "./autoLayout";
 10→import type { MermaidLayoutResult } from "./renderLayout";
 11→
 12→/**
 13→ * Reverse of escapeMermaid: convert Mermaid escape sequences back to original characters.
 14→ */
 15→export function unescapeMermaid(text: string): string {
 16→  return text
 17→    .replace(/#amp;/g, "&")
 18→    .replace(/#quot;/g, '"')
 19→    .replace(/#lt;/g, "<")
 20→    .replace(/#gt;/g, ">")
 21→    .replace(/#lbrace;/g, "{")
 22→    .replace(/#rbrace;/g, "}")
 23→    .replace(/#lpar;/g, "(")
 24→    .replace(/#rpar;/g, ")")
 25→    .replace(/#lbrack;/g, "[")
 26→    .replace(/#rbrack;/g, "]");
 27→}
 28→
 29→// Shape patterns ordered from most specific (longest delimiters) to least specific
 30→const SHAPE_PATTERNS: { open: string; close: string; shape: NodeShape }[] = [
 31→  { open: "((", close: "))", shape: "circle" },
 32→  { open: "([", close: "])", shape: "stadium" },
 33→  { open: "[(", close: ")]", shape: "cylinder" },
 34→  { open: "[[", close: "]]", shape: "predefinedProcess" },
 35→  { open: "{{", close: "}}", shape: "hexagon" },
 36→  { open: "[/", close: "\\]", shape: "document" },
 37→  { open: "[\\", close: "/]", shape: "manualInput" },
 38→  { open: "[/", close: "/]", shape: "parallelogram" },
 39→  { open: "[\\", close: "\\]", shape: "trapezoid" },
 40→  { open: "{", close: "}", shape: "diamond" },
 41→  { open: "(", close: ")", shape: "roundedRect" },
 42→  { open: "[", close: "]", shape: "rectangle" },
 43→];
 44→
 45→function parseNodeDef(raw: string): { id: string; label: string; shape: NodeShape } | null {
 46→  const trimmed = raw.trim();
 47→  if (!trimmed) return null;
 48→
 49→  for (const { open, close, shape } of SHAPE_PATTERNS) {
 50→    const openIdx = trimmed.indexOf(open);
 51→    if (openIdx < 1) continue;
 52→
 53→    const id = trimmed.slice(0, openIdx);
 54→    // Verify the rest ends with close
 55→    const rest = trimmed.slice(openIdx + open.length);
 56→    if (!rest.endsWith(close)) continue;
 57→
 58→    const label = unescapeMermaid(rest.slice(0, rest.length - close.length));
 59→    return { id, label, shape };
 60→  }
 61→
 62→  // No shape delimiters: just an ID reference
 63→  return null;
 64→}
 65→
 66→function getNodeSize(shape: NodeShape): { width: number; height: number } {
 67→  switch (shape) {
 68→    case "diamond":
 69→      return { width: DEFAULT_DIAMOND_SIZE, height: DEFAULT_DIAMOND_SIZE };
 70→    case "circle":
 71→      return { width: DEFAULT_NODE_HEIGHT * 2, height: DEFAULT_NODE_HEIGHT * 2 };
 72→    case "hexagon":
 73→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT + 10 };
 74→    case "cylinder":
 75→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 20 };
 76→    case "document":
 77→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 10 };
 78→    case "predefinedProcess":
 79→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 80→    case "display":
 81→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 82→    default:
 83→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT };
 84→  }
 85→}
 86→
 87→// Split an edge line by arrow patterns, returning segments and labels
 88→const ARROW_RE = /\s*-->\s*(?:\|([^|]*)\|)?\s*/;
 89→
 90→function splitEdgeLine(line: string): { segments: string[]; labels: string[] } | null {
 91→  const segments: string[] = [];
 92→  const labels: string[] = [];
 93→  let remaining = line;
 94→
 95→  while (true) {
 96→    const match = ARROW_RE.exec(remaining);
 97→    if (!match) {
 98→      segments.push(remaining.trim());
 99→      break;
100→    }
101→    segments.push(remaining.slice(0, match.index).trim());
102→    labels.push(match[1] ?? "");
103→    remaining = remaining.slice(match.index + match[0].length);
104→  }
105→
106→  if (segments.length < 2) return null;
107→  return { segments, labels };
108→}
109→
110→// Subgraph padding constants for bounding box calculation
111→const SUBGRAPH_PADDING_X = 40;
112→const SUBGRAPH_PADDING_Y_TOP = 40;
113→const SUBGRAPH_PADDING_Y_BOTTOM = 20;
114→
115→export function parseMermaid(text: string, edgeType?: import("@/types/flow").EdgeType, layout?: MermaidLayoutResult): {
116→  nodes: FlowNode[];
117→  edges: FlowEdge[];
118→  direction: FlowDirection;
119→  nextIdCounter: number;
120→} {
121→  const lines = text.split("\n").map((l) => l.trim()).filter((l) => l.length > 0);
122→  if (lines.length === 0) throw new Error("Empty input");
123→
124→  // Parse direction from first line
125→  const headerMatch = lines[0].match(/^(?:graph|flowchart)\s+(TD|LR|TB|BT)$/i);
126→  if (!headerMatch) throw new Error("Invalid header: expected 'graph TD|LR' or 'flowchart TD|LR'");
127→
128→  let direction: FlowDirection = "TD";
129→  const dirStr = headerMatch[1].toUpperCase();
130→  if (dirStr === "LR") direction = "LR";
131→  // TB and BT both map to TD
132→
133→  // Collect node definitions and edges
134→  const nodeDefs = new Map<string, { label: string; shape: NodeShape }>();
135→  const edgeList: { source: string; target: string; label: string }[] = [];
136→
137→  function registerNode(id: string, label: string, shape: NodeShape) {
138→    // First definition wins for shape/label
139→    if (!nodeDefs.has(id)) {
140→      nodeDefs.set(id, { label, shape });
141→    }
142→  }
143→
144→  function ensureNode(id: string) {
145→    if (!nodeDefs.has(id)) {
146→      nodeDefs.set(id, { label: id, shape: "rectangle" });
147→    }
148→  }
149→
150→  function resolveNodeRef(segment: string): string {
151→    const parsed = parseNodeDef(segment);
152→    if (parsed) {
153→      registerNode(parsed.id, parsed.label, parsed.shape);
154→      return parsed.id;
155→    }
156→    // Plain ID reference
157→    const id = segment.trim();
158→    ensureNode(id);
159→    return id;
160→  }
161→
162→  // Track subgraph contexts for subgraphGroup creation
163→  const subgraphStack: { id: string; label: string }[] = [];
164→  const subgraphLabels = new Map<string, string>();
165→  const nodeToSubgraph = new Map<string, string>();
166→  // Track parent subgraph for nested subgraphs
167→  const subgraphParentMap = new Map<string, string>();
168→
169→  for (let i = 1; i < lines.length; i++) {
170→    const line = lines[i];
171→
172→    // Check for subgraph start
173→    const subgraphMatch = line.match(/^subgraph\s+(\S+?)(?:\[([^\]]*)\])?\s*$/);
174→    if (subgraphMatch) {
175→      const sgId = subgraphMatch[1];
176→      const sgLabel = subgraphMatch[2] ? unescapeMermaid(subgraphMatch[2]) : sgId;
177→      // Track parent subgraph for nesting
178→      if (subgraphStack.length > 0) {
179→        subgraphParentMap.set(sgId, subgraphStack[subgraphStack.length - 1].id);
180→      }
181→      subgraphStack.push({ id: sgId, label: sgLabel });
182→      subgraphLabels.set(sgId, sgLabel);
183→      continue;
184→    }
185→
186→    // Check for end
187→    if (line === "end" && subgraphStack.length > 0) {
188→      subgraphStack.pop();
189→      continue;
190→    }
191→
192→    const currentSubgraph = subgraphStack.length > 0 ? subgraphStack[subgraphStack.length - 1].id : null;
193→
194→    // Try to parse as edge line (contains -->)
195→    const edgeParts = splitEdgeLine(line);
196→    if (edgeParts && edgeParts.segments.length >= 2) {
197→      const { segments, labels } = edgeParts;
198→      const resolvedIds = segments.map((s) => resolveNodeRef(s));
