  1→"use client";
  2→
  3→import { useState } from "react";
  4→import {
  5→  Dialog,
  6→  DialogContent,
  7→  DialogHeader,
  8→  DialogTitle,
  9→  DialogDescription,
 10→  DialogFooter,
 11→} from "@/components/ui/dialog";
 12→import { Button } from "@/components/ui/button";
 13→import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";
 14→import { useLocale } from "@/lib/i18n/useLocale";
 15→import { parseMermaid } from "@/lib/mermaid/parse";
 16→import { renderMermaidLayout } from "@/lib/mermaid/renderLayout";
 17→import { useFlowStore } from "@/store/useFlowStore";
 18→import { toast } from "sonner";
 19→import type { EdgeType } from "@/types/flow";
 20→
 21→const EDGE_TYPE_STORAGE_KEY = "flowmaid-mermaid-edge-type";
 22→
 23→function getStoredEdgeType(): EdgeType {
 24→  if (typeof window === "undefined") return "bezier";
 25→  const stored = localStorage.getItem(EDGE_TYPE_STORAGE_KEY);
 26→  if (stored === "bezier" || stored === "straight" || stored === "step") return stored;
 27→  return "bezier";
 28→}
 29→
 30→interface MermaidImportDialogProps {
 31→  open: boolean;
 32→  onOpenChange: (open: boolean) => void;
 33→  onSuccess?: () => void;
 34→}
 35→
 36→export function MermaidImportDialog({
 37→  open,
 38→  onOpenChange,
 39→  onSuccess,
 40→}: MermaidImportDialogProps) {
 41→  const [text, setText] = useState("");
 42→  const [edgeType, setEdgeType] = useState<EdgeType>(getStoredEdgeType);
 43→  const { t } = useLocale();
 44→  const loadState = useFlowStore((s) => s.loadState);
 45→  const hasContent = useFlowStore((s) => s.nodes.length > 0 || s.edges.length > 0);
 46→
 47→  const handleEdgeTypeChange = (value: string) => {
 48→    if (!value) return;
 49→    const et = value as EdgeType;
 50→    setEdgeType(et);
 51→    localStorage.setItem(EDGE_TYPE_STORAGE_KEY, et);
 52→  };
 53→
 54→  const [loading, setLoading] = useState(false);
 55→
 56→  const doConvert = async () => {
 57→    setLoading(true);
 58→    try {
 59→      // Step 1: Try mermaid.js layout first for accurate positioning
 60→      let layout: Awaited<ReturnType<typeof renderMermaidLayout>> | undefined;
 61→      try {
 62→        layout = await renderMermaidLayout(text);
 63→      } catch (e) {
 64→        console.warn("mermaid.js layout failed, falling back to autoLayout", e);
 65→      }
 66→
 67→      // Step 2: Parse with layout result
 68→      const result = parseMermaid(text, edgeType, layout);
 69→      loadState(result);
 70→      toast.success(t("mermaidImportSuccess"));
 71→      setText("");
 72→      onOpenChange(false);
 73→      onSuccess?.();
 74→    } catch {
 75→      toast.error(t("mermaidParseFailed"));
 76→    } finally {
 77→      setLoading(false);
 78→    }
 79→  };
 80→
 81→  const handleConvert = async () => {
 82→    if (hasContent) {
 83→      if (!window.confirm(t("mermaidOverwriteConfirm"))) return;
 84→    }
 85→    await doConvert();
 86→  };
 87→
 88→  return (
 89→    <Dialog open={open} onOpenChange={onOpenChange}>
 90→      <DialogContent>
 91→        <DialogHeader>
 92→          <DialogTitle>{t("importMermaid")}</DialogTitle>
 93→          <DialogDescription>{t("mermaidImportDesc")}</DialogDescription>
 94→        </DialogHeader>
 95→        <div className="flex items-center gap-2">
 96→          <span className="text-sm text-muted-foreground">{t("edgeTypeLabel")}:</span>
 97→          <ToggleGroup
 98→            type="single"
 99→            value={edgeType}
100→            onValueChange={handleEdgeTypeChange}
101→          >
102→            <ToggleGroupItem value="bezier" className="h-8 px-2 text-xs">
103→              {t("bezier")}
104→            </ToggleGroupItem>
105→            <ToggleGroupItem value="straight" className="h-8 px-2 text-xs">
106→              {t("straight")}
107→            </ToggleGroupItem>
108→            <ToggleGroupItem value="step" className="h-8 px-2 text-xs">
109→              {t("step")}
110→            </ToggleGroupItem>
111→          </ToggleGroup>
112→        </div>
113→        <textarea
114→          className="w-full h-48 rounded-md border border-input bg-background px-3 py-2 text-sm font-mono resize-none focus:outline-none focus:ring-2 focus:ring-ring"
115→          value={text}
116→          onChange={(e) => setText(e.target.value)}
117→          placeholder={"graph TD\n    A[Start] --> B{Condition}\n    B -->|Yes| C[End]"}
118→        />
119→        <DialogFooter>
120→          <Button onClick={handleConvert} disabled={!text.trim() || loading}>
121→            {loading ? "..." : t("convert")}
122→          </Button>
123→        </DialogFooter>
124→      </DialogContent>
125→    </Dialog>
126→  );
127→}
