export function unescapeMermaid(text: string): string {
  let result = text
    .replace(/#amp;/g, "&")
    .replace(/#quot;/g, '"')
    .replace(/#lt;/g, "<")
    .replace(/#gt;/g, ">")
    .replace(/#lbrace;/g, "{")
    .replace(/#rbrace;/g, "}")
    .replace(/#lpar;/g, "(")
    .replace(/#rpar;/g, ")")
    .replace(/#lbrack;/g, "[")
    .replace(/#rbrack;/g, "]");
  // Strip surrounding double quotes (Mermaid quoted labels)
  if (result.startsWith('"') && result.endsWith('"')) {
    result = result.slice(1, -1);
  }
  // Convert <br/> and <br> to newline
  result = result.replace(/<br\s*\/?>/gi, "\n");
  return result;
}

