  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { FlowDirection, NodeShape } from "@/types/flow";
  3→import { MarkerType } from "@xyflow/react";
  4→import {
  5→  DEFAULT_NODE_WIDTH,
  6→  DEFAULT_NODE_HEIGHT,
  7→  DEFAULT_DIAMOND_SIZE,
  8→} from "@/lib/constants";
  9→import { idToCounter } from "@/lib/id";
 10→import { autoLayout } from "./autoLayout";
 11→import type { MermaidLayoutResult } from "./renderLayout";
 12→
 13→/**
 14→ * Reverse of escapeMermaid: convert Mermaid escape sequences back to original characters.
 15→ */
 16→export function unescapeMermaid(text: string): string {
 17→  let result = text
 18→    .replace(/#amp;/g, "&")
 19→    .replace(/#quot;/g, '"')
 20→    .replace(/#lt;/g, "<")
 21→    .replace(/#gt;/g, ">")
 22→    .replace(/#lbrace;/g, "{")
 23→    .replace(/#rbrace;/g, "}")
 24→    .replace(/#lpar;/g, "(")
 25→    .replace(/#rpar;/g, ")")
 26→    .replace(/#lbrack;/g, "[")
 27→    .replace(/#rbrack;/g, "]");
 28→  // Strip surrounding double quotes (Mermaid quoted labels), but only if length > 2
 29→  if (result.length > 2 && result.startsWith('"') && result.endsWith('"')) {
 30→    result = result.slice(1, -1);
 31→  }
 32→  // Convert <br/> and <br> to newline
 33→  result = result.replace(/<br\s*\/?>/gi, "\n");
 34→  return result;
 35→}
 36→
 37→// Shape patterns ordered from most specific (longest delimiters) to least specific
 38→const SHAPE_PATTERNS: { open: string; close: string; shape: NodeShape }[] = [
 39→  { open: "((", close: "))", shape: "circle" },
 40→  { open: "([", close: "])", shape: "stadium" },
 41→  { open: "[(", close: ")]", shape: "cylinder" },
 42→  { open: "[[", close: "]]", shape: "predefinedProcess" },
 43→  { open: "{{", close: "}}", shape: "hexagon" },
 44→  { open: "[/", close: "\\]", shape: "document" },
 45→  { open: "[\\", close: "/]", shape: "manualInput" },
 46→  { open: "[/", close: "/]", shape: "parallelogram" },
 47→  { open: "[\\", close: "\\]", shape: "trapezoid" },
 48→  { open: "{", close: "}", shape: "diamond" },
 49→  { open: "(", close: ")", shape: "roundedRect" },
 50→  { open: "[", close: "]", shape: "rectangle" },
 51→];
 52→
 53→function parseNodeDef(raw: string): { id: string; label: string; shape: NodeShape } | null {
 54→  const trimmed = raw.trim();
 55→  if (!trimmed) return null;
 56→
 57→  for (const { open, close, shape } of SHAPE_PATTERNS) {
 58→    const openIdx = trimmed.indexOf(open);
 59→    if (openIdx < 1) continue;
 60→
 61→    const id = trimmed.slice(0, openIdx);
 62→    // Verify the rest ends with close
 63→    const rest = trimmed.slice(openIdx + open.length);
 64→    if (!rest.endsWith(close)) continue;
 65→
 66→    const label = unescapeMermaid(rest.slice(0, rest.length - close.length));
 67→    return { id, label, shape };
 68→  }
 69→
 70→  // No shape delimiters: just an ID reference
 71→  return null;
 72→}
 73→
 74→function getNodeSize(shape: NodeShape): { width: number; height: number } {
 75→  switch (shape) {
 76→    case "diamond":
 77→      return { width: DEFAULT_DIAMOND_SIZE, height: DEFAULT_DIAMOND_SIZE };
 78→    case "circle":
 79→      return { width: DEFAULT_NODE_HEIGHT * 2, height: DEFAULT_NODE_HEIGHT * 2 };
 80→    case "hexagon":
 81→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT + 10 };
 82→    case "cylinder":
 83→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 20 };
 84→    case "document":
 85→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT + 10 };
 86→    case "predefinedProcess":
 87→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 88→    case "display":
 89→      return { width: DEFAULT_NODE_WIDTH + 20, height: DEFAULT_NODE_HEIGHT };
 90→    default:
 91→      return { width: DEFAULT_NODE_WIDTH, height: DEFAULT_NODE_HEIGHT };
 92→  }
 93→}
 94→
 95→// Split an edge line by arrow patterns, returning segments and labels
 96→// Supports: -->, -.->, ===>, ~~>, -->, etc.
 97→const ARROW_RE = /\s*(?:-+\.?-*>|={2,}>|~{2,}>)\s*(?:\|([^|]*)\|)?\s*/;
 98→
 99→function splitEdgeLine(line: string): { segments: string[]; labels: string[] } | null {
100→  const segments: string[] = [];
101→  const labels: string[] = [];
102→  let remaining = line;
103→
104→  while (true) {
105→    const match = ARROW_RE.exec(remaining);
106→    if (!match) {
107→      segments.push(remaining.trim());
108→      break;
109→    }
110→    segments.push(remaining.slice(0, match.index).trim());
111→    labels.push(match[1] ?? "");
112→    remaining = remaining.slice(match.index + match[0].length);
113→  }
114→
115→  if (segments.length < 2) return null;
116→  return { segments, labels };
117→}
118→
119→// Subgraph padding constants for bounding box calculation
120→const SUBGRAPH_PADDING_X = 40;
121→const SUBGRAPH_PADDING_Y_TOP = 40;
122→const SUBGRAPH_PADDING_Y_BOTTOM = 20;
123→
124→export function parseMermaid(text: string, edgeType?: import("@/types/flow").EdgeType, layout?: MermaidLayoutResult): {
125→  nodes: FlowNode[];
126→  edges: FlowEdge[];
127→  direction: FlowDirection;
128→  nextIdCounter: number;
129→  componentDefinitions: import("@/types/flow").ComponentDefinition[];
130→} {
131→  const lines = text.split("\n").map((l) => l.trim()).filter((l) => l.length > 0);
132→  if (lines.length === 0) throw new Error("Empty input");
133→
134→  // Parse direction from first line
135→  const headerMatch = lines[0].match(/^(?:graph|flowchart)\s+(TD|LR|TB|BT)$/i);
136→  if (!headerMatch) throw new Error("Invalid header: expected 'graph TD|LR' or 'flowchart TD|LR'");
137→
138→  let direction: FlowDirection = "TD";
139→  const dirStr = headerMatch[1].toUpperCase();
140→  if (dirStr === "LR") direction = "LR";
141→  // TB and BT both map to TD
142→
143→  // Collect node definitions and edges
144→  const nodeDefs = new Map<string, { label: string; shape: NodeShape }>();
145→  const edgeList: { source: string; target: string; label: string }[] = [];
146→
147→  function registerNode(id: string, label: string, shape: NodeShape) {
148→    // First definition wins for shape/label
149→    if (!nodeDefs.has(id)) {
150→      nodeDefs.set(id, { label, shape });
151→    }
152→  }
153→
154→  function ensureNode(id: string) {
155→    if (!nodeDefs.has(id)) {
156→      nodeDefs.set(id, { label: id, shape: "rectangle" });
157→    }
158→  }
159→
160→  function resolveNodeRef(segment: string): string {
161→    const parsed = parseNodeDef(segment);
162→    if (parsed) {
163→      registerNode(parsed.id, parsed.label, parsed.shape);
164→      return parsed.id;
165→    }
166→    // Plain ID reference
167→    const id = segment.trim();
168→    ensureNode(id);
169→    return id;
170→  }
171→
172→  // Track subgraph contexts for subgraphGroup creation
173→  const subgraphStack: { id: string; label: string }[] = [];
174→  const subgraphLabels = new Map<string, string>();
175→  const nodeToSubgraph = new Map<string, string>();
176→  // Track parent subgraph for nested subgraphs
177→  const subgraphParentMap = new Map<string, string>();
178→
179→  for (let i = 1; i < lines.length; i++) {
180→    const line = lines[i];
181→
182→    // Check for subgraph start
183→    const subgraphMatch = line.match(/^subgraph\s+(\S+?)(?:\[([^\]]*)\])?\s*$/);
184→    if (subgraphMatch) {
185→      const sgId = subgraphMatch[1];
186→      const rawLabel = subgraphMatch[2] ?? sgId;
187→      const sgLabel = unescapeMermaid(rawLabel);
188→      // Track parent subgraph for nesting
189→      if (subgraphStack.length > 0) {
190→        subgraphParentMap.set(sgId, subgraphStack[subgraphStack.length - 1].id);
191→      }
192→      subgraphStack.push({ id: sgId, label: sgLabel });
193→      subgraphLabels.set(sgId, sgLabel);
194→      continue;
195→    }
196→
197→    // Check for end
198→    if (line === "end" && subgraphStack.length > 0) {
199→      subgraphStack.pop();
200→      continue;
201→    }
202→
203→    const currentSubgraph = subgraphStack.length > 0 ? subgraphStack[subgraphStack.length - 1].id : null;
204→
205→    // Try to parse as edge line (contains -->)
206→    const edgeParts = splitEdgeLine(line);
207→    if (edgeParts && edgeParts.segments.length >= 2) {
208→      const { segments, labels } = edgeParts;
209→      const resolvedIds = segments.map((s) => resolveNodeRef(s));
210→
211→      for (const rid of resolvedIds) {
212→        if (currentSubgraph && !nodeToSubgraph.has(rid)) {
213→          nodeToSubgraph.set(rid, currentSubgraph);
214→        }
215→      }
216→
217→      for (let j = 0; j < resolvedIds.length - 1; j++) {
218→        edgeList.push({
219→          source: resolvedIds[j],
220→          target: resolvedIds[j + 1],
221→          label: labels[j] ?? "",
222→        });
223→      }
224→      continue;
225→    }
226→
227→    // Try to parse as standalone node definition
228→    const parsed = parseNodeDef(line);
229→    if (parsed) {
230→      registerNode(parsed.id, parsed.label, parsed.shape);
231→      if (currentSubgraph && !nodeToSubgraph.has(parsed.id)) {
232→        nodeToSubgraph.set(parsed.id, currentSubgraph);
233→      }
234→    }
235→  }
236→
237→  // Remove nodeDefs entries that conflict with subgraph IDs
238→  // (When a subgraph ID is used as an edge endpoint, ensureNode creates a regular node entry,
239→  //  but the subgraph should be represented as a subgraphGroup node instead)
240→  for (const sgId of subgraphLabels.keys()) {
241→    nodeDefs.delete(sgId);
242→  }
243→
244→  // Layout: use mermaid.js layout if provided, otherwise fall back to autoLayout
245→  let positions: Map<string, { x: number; y: number }>;
246→  let backEdges: Set<string> = new Set<string>();
247→  const sizeMap = new Map<string, { width: number; height: number }>();
248→
249→  if (layout) {
250→    // Use mermaid.js layout result
251→    positions = new Map<string, { x: number; y: number }>();
252→    backEdges = new Set<string>();
253→
254→    for (const [id, def] of nodeDefs) {
255→      const mNode = layout.nodes.get(id);
256→      if (mNode) {
257→        // mermaid.js returns center coordinates; convert to top-left
258→        positions.set(id, {
259→          x: mNode.x - mNode.width / 2,
260→          y: mNode.y - mNode.height / 2,
261→        });
262→        sizeMap.set(id, { width: mNode.width, height: mNode.height });
263→      } else {
264→        const size = getNodeSize(def.shape);
265→        positions.set(id, { x: 0, y: 0 });
266→        sizeMap.set(id, size);
267→      }
268→    }
269→  } else {
270→    // Fall back to autoLayout
271→    const nodeIds = [...nodeDefs.keys()].map((id) => ({ id }));
272→    for (const [id, def] of nodeDefs) {
273→      sizeMap.set(id, getNodeSize(def.shape));
274→    }
275→    const layoutResult = autoLayout(nodeIds, edgeList, direction, sizeMap);
276→    positions = layoutResult.positions;
277→    backEdges = layoutResult.backEdges;
278→  }
279→
280→  // Build FlowNode[]
281→  const nodes: FlowNode[] = [];
282→  let maxCounter = 0;
283→
284→  for (const [id, def] of nodeDefs) {
285→    const pos = positions.get(id) ?? { x: 0, y: 0 };
286→    const size = sizeMap.get(id) ?? getNodeSize(def.shape);
287→
288→    // Track highest alphabetic ID counter
289→    if (/^[A-Z]+$/.test(id)) {
290→      const counter = idToCounter(id);
291→      if (counter + 1 > maxCounter) maxCounter = counter + 1;
292→    }
293→
294→    nodes.push({
295→      id,
296→      type: def.shape,
297→      position: pos,
298→      data: { label: def.label, shape: def.shape },
299→      style: { width: size.width, height: size.height },
300→    });
301→  }
302→
303→  // Handle directions: forward edges follow main axis, back-edges loop via cross axis
304→  const fwdSourceHandle = direction === "LR" ? "right-source" : "bottom-source";
