313→    const sh = isBack ? backSourceHandle : fwdSourceHandle;
314→    const th = isBack ? backTargetHandle : fwdTargetHandle;
315→    const edgeId = `${e.source}-${e.target}-${sh}-${th}`;
316→    edges.push({
317→      id: edgeId,
318→      source: e.source,
319→      target: e.target,
320→      sourceHandle: sh,
321→      targetHandle: th,
