343→  const sgProcessOrder: string[] = [];
344→  const sgProcessed = new Set<string>();
345→  const enqueueSg = (sgId: string) => {
346→    if (sgProcessed.has(sgId)) return;
347→    sgProcessed.add(sgId);
348→    // Process children first (innermost first)
349→    for (const [nestedSgId, parentSgId] of subgraphParentMap) {
