355→  for (const sgId of subgraphLabels.keys()) {
356→    if (!subgraphParentMap.has(sgId)) enqueueSg(sgId);
357→  }
358→  // Also process any that might have been missed (orphan subgraphs)
359→  for (const sgId of subgraphLabels.keys()) enqueueSg(sgId);
360→  // Reverse so innermost comes first
361→  sgProcessOrder.reverse();
