389→      sgSize = { width: sgLayout.width, height: sgLayout.height };
390→    } else {
391→      // Compute bounding box from child positions (all absolute at this point)
392→      let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
393→      // Include regular child nodes
394→      for (const child of childNodes) {
395→        const w = (child.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
396→        const h = (child.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
397→        if (child.position.x < minX) minX = child.position.x;
398→        if (child.position.y < minY) minY = child.position.y;
399→        if (child.position.x + w > maxX) maxX = child.position.x + w;
400→        if (child.position.y + h > maxY) maxY = child.position.y + h;
401→      }
402→      // Include nested subgraph groups (already created in nodes by innermost-first order)
403→      for (const nestedSgId of nestedSgIds) {
404→        const nestedAbsPos = sgAbsPositions.get(nestedSgId);
405→        const nestedSize = sgSizes.get(nestedSgId);
406→        if (nestedAbsPos && nestedSize) {
407→          if (nestedAbsPos.x < minX) minX = nestedAbsPos.x;
408→          if (nestedAbsPos.y < minY) minY = nestedAbsPos.y;
409→          if (nestedAbsPos.x + nestedSize.width > maxX) maxX = nestedAbsPos.x + nestedSize.width;
410→          if (nestedAbsPos.y + nestedSize.height > maxY) maxY = nestedAbsPos.y + nestedSize.height;
