  1→import type { FlowNode, FlowEdge } from "@/store/types";
  2→import type { FlowDirection, ComponentDefinition } from "@/types/flow";
  3→import { nodeToMermaid } from "./nodeToMermaid";
  4→import { escapeMermaid } from "./nodeToMermaid";
  5→import { edgeToMermaid } from "./edgeToMermaid";
  6→
  7→/**
  8→ * Recursively emit a subgraph block for a subgraphGroup node.
  9→ * Handles arbitrary nesting depth. Edges are output at the level where
 10→ * both source and target are direct children (not deeper descendants).
 11→ */
 12→function emitSubgraphBlock(
 13→  sgId: string,
 14→  sgLabel: string,
 15→  nodes: FlowNode[],
 16→  edges: FlowEdge[],
 17→  lines: string[],
 18→): void {
 19→  lines.push(`    subgraph ${sgId}[${escapeMermaid(sgLabel)}]`);
 20→
 21→  const children = nodes.filter((n) => n.data.subgraphParentId === sgId);
 22→  // All direct children IDs (both regular nodes and nested subgraphGroups)
 23→  const allDirectChildIds = new Set<string>();
 24→
 25→  for (const child of children) {
 26→    if (child.data.shape === "text") continue;
 27→    allDirectChildIds.add(child.id);
 28→    if (child.data.isSubgraphGroup) {
 29→      // Recurse into nested subgraph
 30→      emitSubgraphBlock(child.id, child.data.label, nodes, edges, lines);
 31→    } else {
 32→      lines.push(nodeToMermaid(child));
 33→    }
 34→  }
 35→
 36→  // Output edges where both endpoints are direct children of this group
 37→  // (includes edges between regular nodes and nested subgraphGroup nodes)
 38→  for (const edge of edges) {
 39→    if (edge.data?.isBridgeEdge) continue;
 40→    if (allDirectChildIds.has(edge.source) && allDirectChildIds.has(edge.target)) {
 41→      lines.push(edgeToMermaid(edge));
 42→    }
 43→  }
 44→
 45→  lines.push(`    end`);
 46→}
 47→
 48→/**
 49→ * Generate complete Mermaid flowchart syntax from nodes, edges, and direction
 50→ */
 51→export function generateMermaid(
 52→  nodes: FlowNode[],
 53→  edges: FlowEdge[],
 54→  direction: FlowDirection,
 55→  definitions?: ComponentDefinition[]
 56→): string {
 57→  const lines: string[] = [`flowchart ${direction}`];
 58→
 59→  // Build map of component instance IDs to their child nodes
 60→  const instanceChildMap = new Map<string, FlowNode[]>();
 61→  const childNodeIds = new Set<string>();
 62→  for (const node of nodes) {
 63→    if (node.data.componentParentId) {
